INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('SV-SVC-VOA-01', 'E-Visa Support Service', 'Online e-visa application assistance', 'Service', 'Visa', 'All Vietnam', 'Standard', $imp3$Full assistance with Vietnam e-visa application for eligible nationalities. Document checklist, form guidance, and confirmation follow-up. Processing time: 3 business days standard.$imp3$, 'The Ant Adventures team', '', 'services') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('SV-SGN-HD-01', 'Arrival Fast Track (Airport)', 'VIP arrival lane | Meet & greet | Immigration fast track | Luggage', 'Service', 'Transfer', 'SGN / HAN / DAD', 'Standard', $imp4$VIP meet-and-greet service at Tan Son Nhat (SGN), Noi Bai (HAN), or Da Nang (DAD) airport. Representative meets clients before immigration, assists through priority lane, and escorts to private transfer vehicle. Luggage handling included.$imp4$, 'The Ant Adventures operations team', '', 'services') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('SV-SGN-HD-02', 'Departure Fast Track (Airport)', 'VIP departure | Check-in assistance | Priority security | Lounge', 'Service', 'Transfer', 'SGN / HAN / DAD', 'Standard', $imp5$VIP departure assistance at Tan Son Nhat (SGN), Noi Bai (HAN), or Da Nang (DAD). Representative meets clients at the airport entrance, assists with check-in, escorts through priority security, and arranges lounge access where available.$imp5$, 'The Ant Adventures operations team', '', 'services') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-TRF-01', 'Hanoi: Noi Bai Airport → Hotel Private Transfer', 'Private vehicle | Meet & greet | Luggage assistance | Door-to-door', 'Half Day', 'Transfer', 'Hanoi', 'Easy & Comfortable', $imp6$The journey from Noi Bai International Airport into the heart of Hanoi — some 30 kilometres of expressway dissolving into the French Quarter's broad boulevards — sets the tone for every experience that follows. This private transfer places a dedicated driver and comfortable, air-conditioned vehicle at the arrivals gate, where a representative stands with a personalised name board and the quiet efficiency of a team that has met a thousand flights and knows precisely how to make the first hour of $imp6$, $imp7$• Private vehicle, driver & representative — personalised namecard, zero waiting  • Luggage handled door to door — from carousel to hotel lobby  • Air-conditioned comfort with chilled water and face towels en route  • *Vehicle, driver, fuel, parking,$imp7$, 'On request', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-TRF-02', 'Hanoi: Hotel → Noi Bai Airport Private Transfer', 'Private vehicle | Luggage assistance | On-time guarantee | Door-to-door', 'Half Day', 'Transfer', 'Hanoi', 'Easy & Comfortable', $imp8$The departure from Hanoi deserves to be as graceful as the arrival, and this private transfer from hotel to Noi Bai International Airport ensures that the city's final impression is one of ease rather than anxiety. A dedicated driver collects guests from the hotel lobby at the precise time agreed — calculated with the traffic intelligence of a team that monitors the expressway daily — and the journey unfolds without urgency, with space for a last look at the streets, a final photograph through t$imp8$, $imp9$• Punctual hotel pickup — departure time calculated for your specific flight  • Luggage handled lobby to check-in drop-off — no heavy lifting required  • Air-conditioned comfort with chilled water and face towels en route  • *Vehicle, driver, fuel, p$imp9$, 'On request', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-01', 'Path of History: The Sofitel Metropole History Tour', $imp10$Path of History: The Sofitel Metropole History Tour (~ 1 hr, 18:00 – 19:00) The Sofitel Metropole's "Path of History" ha$imp10$, 'Half Day', 'Cultural', 'Hanoi', 'Easy & Comfortable', $imp11$Step inside one of Southeast Asia's most storied hotels and uncover the hidden histories that shaped a nation. The legendary Sofitel Legend Metropole Hanoi has sheltered writers, diplomats, and revolutionaries since 1901, and this exclusive behind-the-scenes journey reveals the layers of intrigue concealed behind its white colonial façade. Walk the secret wartime bunker where guests once sheltered from bombing raids, and hear the extraordinary stories of figures who passed through its gilded hal$imp11$, $imp12$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Path of History: The Sofitel Metropole History Tour$imp12$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-02', 'Hanoi: Market and Street Food', $imp13$Hanoi: Market and Street Food (~ 08:00 - 13:30, 15:30 - 19:30 ) Are you ready for a fun adventure? Most of the areas vis$imp13$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp14$Hanoi's markets are a symphony of colour, fragrance, and ancient commerce that has sustained the city for centuries. This intimate morning excursion plunges you into the beating heart of the Old Quarter's trading culture, where vendors arrange mountains of dragon fruit, aromatic herbs, and fresh-caught fish with artistic precision. A private guide navigates you through lanes that have specialised in the same trade for generations, pausing to introduce artisans, traders, and cooks whose families $imp14$, $imp15$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Are you ready for a fun adventure? Most of the areas visited will be outside of the$imp15$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-03', 'Hanoi: Culture and Culinary Experience by Scooter', $imp16$Hanoi: Culture and Culinary Experience by Scooter (~ 08:00 – 12:00, 13:00 - 17:00) Hanoi is the bustling capital city of$imp16$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp17$There is no more liberating way to read a city than from the back of a scooter, and Hanoi rewards this perspective with extraordinary generosity. A private guide leads this intimate circuit through temple-lined lanes, past crumbling French villas swathed in bougainvillea, and along the willow-fringed shore of Truc Bach Lake. The route weaves between landmarks rarely visited by passing tourists — neighbourhood pagodas fragrant with incense, sidewalk kitchens where pho simmers over wood fires, and$imp17$, $imp18$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Culture and Culinary Experience by Scooter$imp18$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-04', 'Hanoi: Bat Trang Ceramic Village Half Day Cycling (L)', $imp19$Hanoi: Bat Trang Ceramic Village Half Day Cycling (L) Your cycling guide will meet you at your hotel reception at 8am fo$imp19$, 'Half Day', 'Cycling', 'Hanoi', 'Easy & Comfortable', $imp20$The ancient ceramic village of Bat Trang has supplied Hanoi's emperors and merchants with exquisite pottery for over six centuries, and its kilns still glow today. This leisurely half-day cycling journey follows the Red River dike road south from the city, passing rice paddies and water buffalo before arriving at the village's labyrinthine lanes. A private guide introduces you to master potters who learned their craft from their parents and grandparents, and the workshop visit offers an opportun$imp20$, $imp21$Cycling immersion through rice paddies — meditative pace, ground-level discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Bat Trang Ceramic Village Half Day Cycling (L)$imp21$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-05', 'Hanoi: Night Market & Old Quarter with Guide (Street Food) Walking', $imp22$Hanoi: Night Market & Old Quarter with Guide (Street Food) Walking Heading out on foot with your guide in the evening ar$imp22$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp23$**Hanoi: Night Market ****&**** Old Quarter with Guide (Street Food) Walking** As evening falls, Hanoi's Old Quarter transforms into a living canvas of lantern light, street food aromas, and contagious energy that no dinner reservation can replicate. This private evening walk traces the pedestrianised streets of the Hoan Kiem neighbourhood at their most enchanting, when locals reclaim the lanes for badminton, folk music, and long communal meals on plastic stools. A knowledgeable guide introduces$imp23$, $imp24$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Night Market & Old Quarter with Guide (Street Food) Walking$imp24$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-06', $imp25$Hanoi: The Insider's Hanoi by Vespa Adventures - Private (S)$imp25$, $imp26$Hanoi: The Insider's Hanoi by Vespa Adventures - Private (S) Explore the iconic narrow streets of this incredible capita$imp26$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp27$Vespa Adventures pioneered the art of exploring Vietnamese cities by vintage scooter, and their private Hanoi experience remains the gold standard for discerning travellers seeking something beyond the ordinary. Your expert guide — part historian, part storyteller — leads a bespoke route through neighbourhoods that reward curiosity: a hidden pagoda draped in moss, a French-era villa converted into a family home, a narrow alley where silk weavers work at handlooms by natural light. The itinerary $imp27$, $imp28$Ground-level exploration by scooter — backstreet addresses no tour bus can navigate · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: The Insider's Hanoi by Vespa Adventures - Private (S)$imp28$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-07', 'Hanoi: Meeting with Vietnam Air Force War Veteran', 'Hanoi: Meeting with Vietnam Air Force War Veteran Mr.', 'Half Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp29$To spend an afternoon with a Vietnamese Air Force veteran is to receive a living history lesson of remarkable depth and nuance. This profoundly personal experience pairs you with a former pilot or ground crew officer who served during the American War, now willing to share memories rarely voiced in public — of camaraderie, ingenuity, and the sky above Hanoi during those defining years. Through a skilled interpreter, the conversation moves from wartime recollections to life in a changed Vietnam, $imp29$, $imp30$In-depth military history access — context, stories, and sites beyond the guidebook · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Meeting with Vietnam Air Force War Veteran$imp30$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-08', 'Hanoi: Private Meeting with a Water Puppet Artisan', $imp31$Hanoi: Private Meeting with a Water Puppet Artisan Moving to another part of the city we have arranged for you to attend$imp31$, 'Half Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp32$Water puppetry is one of Vietnam's most distinctive and ancient art forms, born in the flooded rice paddies of the Red River Delta over a thousand years ago, and this private encounter grants access to a world ordinarily hidden from audiences. A master artisan — likely a descendant of a long theatrical lineage — opens his workshop to reveal the ingenious wooden figures, the bamboo rods concealed beneath the water's surface, and the narrative traditions that bring each performance to life. The co$imp32$, $imp33$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Private Meeting with a Water Puppet Artisan$imp33$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-09', 'Hanoi: A Step Back in Time to Nom Village (L)', $imp34$Hanoi: A Step Back in Time to Nom Village (L) Your guide and driver will transfer you to Nom Village.$imp34$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp35$Nom Village lies just beyond Hanoi's edge yet feels utterly removed from the urban world — a place where ancient banyan trees shade communal wells and life moves to rhythms unchanged for centuries. This private half-day excursion transports guests to one of the Red River Delta's most atmospheric Bronze Age settlements, where a community of skilled artisans still practises the brass-casting and lacquerware traditions for which the village has long been celebrated. A knowledgeable guide walks you $imp35$, $imp36$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: A Step Back in Time to Nom Village (L)$imp36$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-10', 'Hanoi: Walking Orientation with Guide (Street Food)', $imp37$Hanoi: Walking Orientation with Guide (Street Food) Heading out on foot with your guide around Hoan Kiem Lake and the Ol$imp37$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp38$The best way to arrive in any new city is on foot, and Hanoi rewards the walking visitor with an extraordinary density of layered history concentrated into its ancient streets. This private orientation walk with a passionate local guide charts a course through the 36 guild streets of the Old Quarter, past the iconic red bridge of Hoan Kiem Lake, and alongside the French-era villas that line the broad boulevards leading south. The guide pauses to decode the city's architectural languages — Vietna$imp38$, $imp39$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Walking Orientation with Guide (Street Food)$imp39$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-11', 'Hanoi: Private Afternoon Tea at 94 Hang Bong Ancient House (S)', $imp40$Hanoi: Private Afternoon Tea at 94 Hang Bong Ancient House (S) Meet with our lovely host family at their Ancient House a$imp40$, 'Half Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp41$Tucked within the layered history of the Old Quarter, the ancient house at 94 Hang Bong stands as one of Hanoi's most perfectly preserved merchant homes — a labyrinthine dwelling of dark timber, mosaic courtyards, and ancestral altars that has sheltered the same family for generations. This exclusive private afternoon tea transforms the home into an intimate salon, where your hosts receive guests with the quiet grace of a tradition that predates the colonial era by centuries. A curated selection$imp41$, $imp42$Private tasting workshop with specialist artisan — sensory depth and cultural context · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Private Afternoon Tea at 94 Hang Bong Ancient House (S)$imp42$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-12', 'Hanoi: 1 Hour Cyclo Tour', $imp43$Hanoi: 1 Hour Cyclo Tour Take a one-hour cyclo tour of this charming capital city.$imp43$, 'Half Day', 'Experience', 'Hanoi', 'Easy & Comfortable', $imp44$The cyclo — that iconic three-wheeled pedal carriage — has navigated Hanoi's streets since the French colonial era, and an hour aboard one remains the most elegantly unhurried way to absorb the city's atmosphere. A private cyclo driver and accompanying guide chart a curated route through the Old Quarter's most evocative lanes, gliding past silk merchants, paper lantern workshops, and temple gates draped in incense smoke. The low vantage point places you at eye level with street life in all its s$imp44$, $imp45$Vintage cyclo through the 36 ancient craft streets — Hanoi at its most intimate · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Take a one-hour cyclo tour of this charming capital city. Your guide will tell you about$imp45$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-13', 'Hanoi: 1 Hour Water Puppet Show with Guide', $imp46$Hanoi: 1 Hour Water Puppet Show with Guide In the evening attend a traditional water puppet show unique to Vietnamese cu$imp46$, 'Half Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp47$The water puppet theatre is one of Vietnam's most singular cultural pleasures, and this private experience elevates it from spectacle to genuine artistic encounter. A dedicated guide accompanies you to one of Hanoi's finest puppet theatres, providing a pre-show briefing that transforms the performance from charming folklore into a richly layered narrative tradition rooted in royal courts and monsoon seasons. The one-hour show features dragons breathing real fire across the water's surface, celes$imp47$, $imp48$UNESCO water puppet art form — 1,000-year-old Vietnamese theatrical tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: 1 Hour Water Puppet Show with Guide$imp48$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-14', 'Hanoi: Dinner with Guide (D)', $imp49$Hanoi: Dinner with Guide (D) Enjoy a delicious dinner at one of our recommended restaurants.Private vehicle & driver, En$imp49$, 'Half Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp50$Dinner in Hanoi, when guided by someone who knows the city intimately, becomes a journey through culture and memory rather than merely a meal. This private evening experience pairs guests with a knowledgeable local guide who leads an unhurried progression through the Old Quarter's finest culinary addresses — from a family-run phở house whose broth has simmered for twelve hours to a rooftop bún bò Nam Bộ spot known only to discerning Hanoians. The guide narrates the history, ingredients, and regi$imp50$, $imp51$Curated evening experience — the city at its most atmospheric and alive · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Enjoy a relaxing meal sampling the delicious cuisine of Vietnam. Your guide will be on hand to t$imp51$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-15', 'Hanoi: Private Cooking Class (L)', $imp52$Hanoi: Private Cooking Class (L) Today you will meet Chef Mai, a very talented chef known in the area for her innovative$imp52$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp53$Vietnamese cuisine rewards those who learn it from the inside, and a private cooking class in a Hanoi kitchen is one of travel's most rewarding half-days. Your chef — selected for both culinary mastery and the ability to teach with warmth and humour — begins with a guided market visit to select ingredients whose provenance and seasonality will shape the entire experience. Back in a well-equipped private kitchen, the lesson covers the foundational principles of Vietnamese flavour balance: the int$imp53$, $imp54$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Today you will meet Chef Mai, a very talented chef known in the area for her innova$imp54$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-16', 'Hanoi: Half Day City Highlights (L or D)', $imp55$Hanoi: Half Day City (L) Begin your half-day by discussing with your guide what you would like to do and see. There are $imp55$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp56$Hanoi's greatest landmarks reward the traveller who approaches them with context and curiosity, and this private city highlights experience delivers both in equal measure. A passionate guide leads an intimate circuit encompassing the Ho Chi Minh Mausoleum complex, the One Pillar Pagoda, the Temple of Literature, and the timeless shores of Hoan Kiem Lake, pausing at each to share not just facts but the living stories embedded in stone and ceremony. The itinerary is adapted to the time of day — mo$imp56$, $imp57$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Your guide will discuss and agree on your personalised experience with you in advance.$imp57$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-17', 'Hanoi: Full Day City Highlights (L)', $imp58$Hanoi: Full Day City Highlights (L) Your guide will discuss and agree on your personalised experience with you in advanc$imp58$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp59$For guests with a full day to commit to Hanoi's extraordinary depth, this extended city journey charts a comprehensive course through eight centuries of Vietnamese history concentrated into a single vibrant capital. Morning is given to the imperial axis — the Ho Chi Minh complex, the Temple of Literature, and the Flag Tower — while the afternoon dissolves into the organic labyrinth of the Old Quarter's 36 guild streets, where the city's merchant soul still beats at every corner. A private guide $imp59$, $imp60$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Your guide will discuss and agree on your personalised experience with you in advance.$imp60$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-18', 'Hanoi: Private Photography Explorer (B)', $imp61$Hanoi: Private Photography Explorer (B) Your driver will collect you from your hotel this morning to take you to the mee$imp61$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp62$Hanoi exists in extraordinary photographic light — the low morning glow filtering through cathedral trees, the golden hour igniting colonial façades, the blue dusk settling over the Old Quarter's rooftops — and this private photography excursion is designed to capture it all. A specialist guide with deep knowledge of the city's visual character leads an early-morning or late-afternoon circuit to locations chosen for their aesthetic richness: a moss-draped alley where monks collect alms, a flower$imp62$, $imp63$Expert photography access — prime locations at optimal light, specialist local knowledge · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Your driver will collect you from your hotel this morning to take you to the me$imp63$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-19', 'Hanoi: Private Jeep Tour (L)', $imp64$Hanoi: Private Jeep Tour (L) It is fun to explore Hanoi by jeep exposing you to all sides of Hanoi and the Hanoians who $imp64$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp65$The private jeep has long been the vehicle of choice for those who wish to move between Hanoi's worlds with panache — from the broad boulevards of the French Quarter to the narrow lanes of the ancient city and out to the rural fringes where the capital dissolves into rice paddy and river. This bespoke half-day journey uses a beautifully restored vintage jeep as both transport and centrepiece, drawing admiring glances at every stop. The route is crafted around your interests — architectural herit$imp65$, $imp66$Private vintage Jeep — off-schedule, entirely personal, military history depth · Hanoi: 1,000 years of history, culture, and flavour layered into every street · It is fun to explore Hanoi by jeep exposing you to all sides of Hanoi and the Hanoians wh$imp66$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-20', 'Hanoi: Market, Ancient History and Art Half Day (L or D)', $imp67$Hanoi: Market, Ancient History and Art Half Day (L or D) Your guide will share some ideas, discuss and agree on a plan w$imp67$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp68$Hanoi's markets have served as the city's social and commercial heart for centuries, and this curated half-day weaves together three of the capital's most compelling experiences: the vivid theatre of the Old Quarter market, the layered history of the Hoa Lo Prison and Temple of Literature, and the quiet world of a master lacquerware artist working in his private atelier. A skilled private guide binds these elements into a coherent narrative — commerce, history, and craft as the three pillars of $imp68$, $imp69$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Market, Ancient History and Art Half Day (L or D)$imp69$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-21', 'Hanoi: Cycling West Lake & Fun with Fabric Art (S,L)', $imp70$Hanoi: Cycling West Lake & Fun with Fabric Art (S,L) With your cycling guide transfer to the starting point for your rou$imp70$, 'Half Day', 'Cycling', 'Hanoi', 'Easy & Comfortable', $imp71$**Hanoi: Cycling West Lake ****&**** Fun with Fabric Art (S,L)** West Lake — Hanoi's largest and most serene body of water — offers a very different face of the city from the frenetic Old Quarter, and this gentle cycling experience reveals its pleasures at the most rewarding pace. The route circles the lake's leafy shoreline past ancient pagodas, flower farms supplying the city's florists, and colonial villas converted into boutique guesthouses and galleries. The midpoint of the journey brings a$imp71$, $imp72$Cycling immersion through rice paddies — meditative pace, ground-level discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Cycling West Lake & Fun with Fabric Art (S,L)$imp72$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-22', 'Hanoi: Private Lacquerware Art Class', $imp73$Hanoi: Private Lacquerware Art Class We have arranged for a private class to learn first hand about the Vietnamese tradi$imp73$, 'Half Day', 'Cycling', 'Hanoi', 'Easy & Comfortable', $imp74$Vietnamese lacquerware represents one of the country's most ancient and technically demanding art forms, requiring dozens of painstaking layers applied over weeks or months to achieve the luminous depth that makes a finished piece so captivating. This private class opens the door to that world, placing you in the studio of a master lacquerware artist who has devoted a lifetime to perfecting the craft. The session begins with an explanation of materials — the raw sap tapped from rhus trees, the g$imp74$, $imp75$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · We have arranged for a private class to learn first hand about the Vietnamese traditional $imp75$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-23', 'Hanoi: Half Day City Extension (L)', $imp76$Hanoi: Half Day City Extension (L) Cover those last few experiences you haven't yet managed to slot in, or even revisit $imp76$, 'Half Day', 'Experience', 'Hanoi', 'Easy & Comfortable', $imp77$This elegant half-day extension is designed for guests who have already explored Hanoi's headline monuments and are ready to move into the city's quieter, more personal register. A private guide curates a route through the neighbourhoods that most visitors never reach — the residential blocks west of the citadel where French-era villas wear their age with distinction, the incense-scented lanes of the Old Quarter's northern fringe, and the artisan workshops where furniture makers, silk weavers, a$imp77$, $imp78$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Cover those last few experiences you haven't yet managed to slot in, or even revisit n$imp78$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-24', 'Hanoi: Private Jeep Tour (D) *Military Historical Focussed', $imp79$Hanoi: Private Jeep Tour (D) *Military Historical Focussed (~ 14:00 - 19:00) It is fun to explore Hanoi by jeep exposing$imp79$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp80$Hanoi's role in the American War — known here as the War of Resistance — left an indelible mark on the city's landscape, psyche, and collective memory, and this private evening jeep tour interprets that history with remarkable directness and nuance. A guide with specialist military knowledge leads a circuit of sites that witnessed the war's defining moments in the north: the Long Bien Bridge pockmarked by bombing raids, the B-52 wreckage lying in the shallow water of Huu Tiep Lake, and the Hoa L$imp80$, $imp81$Private vintage Jeep — off-schedule, entirely personal, military history depth · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Private Jeep Tour (D) *Military Historical Focussed$imp81$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-25', 'Hanoi: 4 Hour "Di Vong Vong" on Scooter (D)', $imp82$Hanoi: 4 Hour "Di Vong Vong" on Scooter (D) Hanoi in the evening brings a joyful spirit to anyone joining in the Vietnam$imp82$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp83$'Di vong vong' — the Vietnamese art of going around without particular urgency — captures perfectly the spirit of this four-hour scooter journey through Hanoi as dusk transforms the city into something luminous and alive. A skilled guide navigates you through an evening circuit that prioritises feeling over itinerary: the smell of grilling corn on the roadside, the sound of live music drifting from a communal house, the sight of families gathering around plastic tables for their evening meal as $imp83$, $imp84$Ground-level exploration by scooter — backstreet addresses no tour bus can navigate · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: 4 Hour "Di Vong Vong" on Scooter (D)$imp84$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-26', 'Hanoi: Hidden Hanoian Cultural Stories', 'Hanoi: Hidden Hanoian Cultural Stories (~ 08:00 - 13:00) Ms.', 'Half Day', 'Adventure', 'Hanoi', 'Easy & Comfortable', $imp85$Every city has a story it tells tourists and a story it keeps for itself, and this private journey is devoted entirely to the second kind. A guide who has spent years excavating Hanoi's lesser-known histories leads an intimate walk through the architectural and cultural curiosities that most itineraries overlook — a colonial-era printing house that once produced revolutionary pamphlets, a communal house hidden behind a restaurant façade, a courtyard where a family of traditional mask-makers work$imp85$, $imp86$Exclusive private access — encounters and experiences not available on standard itineraries · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Ms. Nhi, our expert in cultural history and ethnology, has taken time out of$imp86$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-27', $imp87$Hanoi: New Year's Eve Fun in Hanoi$imp87$, $imp88$Hanoi: New Year's Eve Fun in Hanoi (~ 18:30 - 20:30) It's New Year's Eve, Hanoi is your vibrant and exciting playground $imp88$, 'Half Day', 'Adventure', 'Hanoi', 'Easy & Comfortable', $imp89$New Year's Eve in Hanoi is unlike anywhere else in Southeast Asia — a night when the entire city converges on Hoan Kiem Lake for a spontaneous, joyful celebration that unfolds organically through music, fireworks, street food, and the kind of communal happiness that is impossible to manufacture. This private evening experience positions you perfectly to enjoy every dimension of the celebration, with a guide who knows the best vantage points, the finest street food stations, and the local customs$imp89$, $imp90$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · It's New Year's Eve, Hanoi is your vibrant and exciting playground for celebrating and$imp90$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-28', 'Hanoi: Private Market and Street Food Experience with Chef Mai', $imp91$Hanoi: Private Market and Street Food Experience with Chef Mai (~ 08:00 - 13:00) Today, you will be personally accompani$imp91$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp92$Chef is one of Hanoi's most celebrated culinary personalities — a chef whose deep reverence for Vietnamese ingredient traditions and market wisdom has made him a trusted guide for guests who approach food as a form of cultural immersion. This private morning experience begins before sunrise at the Old Quarter's most atmospheric market, where Chef Minh selects each ingredient with the precision of an artist choosing pigments, explaining the provenance, seasonality, and culinary destiny of everyth$imp92$, $imp93$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Private Market and Street Food Experience with Chef Mai$imp93$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-29', 'Hanoi: Private Home Cooking Class with Ms. Hang', 'Hanoi: Private Home Cooking Class with Ms.', 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp94$Ms. Hang has been welcoming guests into her home kitchen for years, and her cooking class remains one of Hanoi's most intimate and authentic culinary experiences — less a formal lesson than a morning spent cooking and eating with a knowledgeable and generous new friend. The session begins with a guided shopping trip to a local wet market where Ms. Hang knows every vendor by name, selecting the freshest herbs, the finest rice noodles, and the most fragrant lemongrass with the confidence of someon$imp94$, $imp95$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Private Home Cooking Class with Ms. Hang$imp95$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-30', $imp96$Hanoi: Children's Fun Discovery With The Nom Village Community$imp96$, $imp97$Hanoi: Children's Fun Discovery With The Nom Village Community (~ 08:00 - 13:00, 1 hr transfer each way) Nom Village is $imp97$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp98$Nom Village is more than an excursion — it is an education in what sustainable, dignified community life can look like, and this specially designed family programme invites children and parents to participate actively in that world rather than merely observe it. Young guests are welcomed by local children as genuine playmates, engaging in traditional games, simple craft activities, and communal tasks that have shaped village life for generations. Parents, meanwhile, discover the village's ancien$imp98$, $imp99$Thoughtfully designed for families — engaging, educational, genuinely fun for all ages · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Children's Fun Discovery With The Nom Village Community$imp99$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-31', 'Hanoi: Private Maison Marou Chocolate Tasting Workshop', $imp100$Hanoi: Private Maison Marou Chocolate Tasting Workshop (~ 1 hour) Join the chocolatier team at Maison Marou to learn abo$imp100$, 'Half Day', 'Arts & Crafts', 'Hanoi', 'Easy & Comfortable', $imp101$Maison Marou has elevated Vietnamese cacao into an international fine chocolate phenomenon, and this private tasting workshop at their Hanoi atelier offers an extraordinarily pleasurable afternoon of discovery. Beginning with a guided education in the geography and agriculture of Vietnam's cacao-growing regions — from the red soils of Ben Tre to the highlands of Lam Dong — the session moves into a sensory exploration of single-origin chocolates whose flavour profiles are as varied and distinctiv$imp101$, $imp102$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Private Maison Marou Chocolate Tasting Workshop$imp102$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-32', 'Indigo Dyeing Workshop', $imp103$Indigo Dyeing Workshop (~2 hours) We have arranged for you to have fun with a hands-on experience creating traditional i$imp103$, 'Half Day', 'Cultural', 'Hanoi', 'Easy & Comfortable', $imp104$The art of indigo dyeing — of transforming plain cloth into something rich with colour, pattern, and meaning through entirely natural means — has been practised by the hill tribes of northern Vietnam for centuries, and this private workshop offers genuine immersion in that tradition. A master dyer guides the session from the preparation of the indigo vat — a living, fermenting culture that requires tending like a garden — through the application of wax resist patterns and the slow revelation of $imp104$, $imp105$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · We have arranged for you to have fun with a hands-on experience creating traditional indig$imp105$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-33', 'Hanoi: Special Access Traditional Music Experience with Mr. Khanh', 'Hanoi: Special Access Traditional Music Experience with Mr.', 'Half Day', 'Cultural', 'Hanoi', 'Easy & Comfortable', $imp106$Mr. Nguyen has dedicated his life to the preservation and performance of ca tru — a Vietnamese chamber music tradition so ancient and refined that UNESCO lists it among the world's intangible cultural heritages in urgent need of safeguarding. This extraordinary private evening grants exclusive access to a performance and conversation in the intimate setting of Mr. Nguyen's practice space, where the interplay of the three-stringed dan day lute, the bamboo percussion, and the singer's extraordinar$imp106$, $imp107$Exclusive private access — encounters and experiences not available on standard itineraries · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Special Access Traditional Music Experience with Mr. Khanh$imp107$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-34', $imp108$Hanoi: Curated Women's Museum$imp108$, $imp109$Hanoi: Curated Women's Museum Your guide and driver will take you to visit one of the most interesting museums in Hanoi $imp109$, 'Half Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp110$The Vietnam Women's Museum is among the most thoughtfully conceived and emotionally resonant museums in Southeast Asia, and this private guided visit unlocks its extraordinary collection with an expert who can contextualise every exhibit within the full sweep of Vietnamese women's experience. From the legendary female generals who commanded armies against Chinese occupation two thousand years ago to the contemporary artists and scientists reshaping modern Vietnam, the museum's narrative is one o$imp110$, $imp111$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Your guide and driver will take you to visit one of the most interesting museums in Ha$imp111$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-35', 'Hanoi: Full Day Architectural Treasures of Hanoi & Meeting with Historian', $imp112$Hanoi: Full Day Architectural Treasures of Hanoi & Meeting with Historian (~ 09:00 - 17:30, flexible) Hanoi is often ass$imp112$, 'Half Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp113$**Hanoi: Full Day Architectural Treasures of Hanoi ****&**** Meeting with Historian** Hanoi's architectural heritage is one of the most layered and visually stimulating in Asia — a palimpsest of Vietnamese imperial tradition, Chinese merchant influence, and French colonial ambition compressed into a city that somehow reconciles them all with remarkable elegance. This private full-day journey dedicated to the city's built environment is led by an architectural historian whose knowledge extends fr$imp113$, $imp114$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Full Day Architectural Treasures of Hanoi & Meeting with Historian$imp114$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-HD-36', 'Hanoi: Special Access Dinner with Artist Thanh Thuc', 'Hanoi: Special Access Dinner with Artist Thanh Thuc (~ 3 hrs) Mrs.', 'Half Day', 'Arts & Crafts', 'Hanoi', 'Easy & Comfortable', $imp115$Artist Thanh Thuc opens her private studio and dining table to a strictly limited number of guests each week, creating one of Hanoi's most sought-after and genuinely intimate cultural evenings. The visit begins in the studio itself, where works in progress reveal the artist's meticulous lacquerware practice — layers of colour built up over months, each application requiring perfect humidity, temperature, and patience before the next can begin. The conversation that follows, animated by the artis$imp115$, $imp116$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Special Access Dinner with Artist Thanh Thuc$imp116$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-FD-01', 'Hanoi: Cooking, Traditions & Cycling in Duong Lam Village (L)', $imp117$Hanoi: Cooking, Traditions & Cycling in Duong Lam Village (L) It is best to start earlier today so as to enjoy the coole$imp117$, 'Full Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp118$**Hanoi: Cooking, Traditions ****&**** Cycling in Duong Lam Village (L)** Duong Lam is Vietnam's best-preserved ancient village, a place of extraordinary beauty where laterite stone walls, centenarian banyan trees, and communal wells speak of a settled agricultural life unchanged for hundreds of years — and this full-day journey makes the most of every dimension it has to offer. The morning begins with an engaging private cooking lesson in a traditional family home, where the host teaches the re$imp118$, $imp119$Cycling immersion through rice paddies — meditative pace, ground-level discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Cooking, Traditions & Cycling in Duong Lam Village (L)$imp119$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-FD-02', 'Hanoi: Full Day City Highlights (L)', $imp120$Hanoi: Full Day City Tour (L) Hanoi, originally named Thang Long or "City of the Ascending Dragon," became the capital o$imp120$, 'Full Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp121$A full day in Hanoi with a dedicated private guide offers the luxury of depth rather than breadth — the ability to linger where curiosity demands and move on only when the moment feels complete. This comprehensive city experience begins at the Ho Chi Minh complex as the morning crowds are still thin, allowing unhurried contemplation of the mausoleum, the stilted house, and the presidential gardens before moving to the Temple of Literature's timeless stone courtyards. After lunch at a restaurant $imp121$, $imp122$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Your guide will discuss and agree on your personalised experience with you in advance.$imp122$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-FD-03', 'Hanoi: Full Day Artist & Architecture Immersion (S,L)', $imp123$Hanoi: Full Day Artist & Architecture Immersion (S,L) Hanoi is often associated with its stunning colonial architecture,$imp123$, 'Full Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp124$**Hanoi: Full Day Artist ****&**** Architecture Immersion (S,L)** Hanoi has nurtured one of Southeast Asia's most dynamic contemporary art scenes, and this full-day immersion places you at its beating centre — in the studios of working artists, the galleries of innovative curators, and the architectural wonders that have inspired Vietnamese creativity for centuries. Morning is devoted to the city's architectural heritage: the Temple of Literature, the colonial villas of Ba Dinh, and the hidden c$imp124$, $imp125$Master artisan access — hands-on participation in a living cultural tradition · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Full Day Artist & Architecture Immersion (S,L)$imp125$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-FD-04', 'Hanoi: Full Day Architectural Treasures of Hanoi by Car (L)', $imp126$Hanoi: Full Day Architectural Treasures of Hanoi by Car (L) Hanoi is often associated with its stunning colonial archite$imp126$, 'Full Day', 'Nature', 'Hanoi', 'Easy & Comfortable', $imp127$This dedicated architectural day is the most thorough and expert-led exploration of Hanoi's extraordinary built environment available to private guests. An architectural historian of considerable authority leads an unhurried full-day circuit encompassing the city's five great architectural eras: the Vietnamese imperial tradition represented by the Temple of Literature and the 36-guild Old Quarter; the Chinese merchant influence visible in the communal houses and clan temples; the French colonial$imp127$, $imp128$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Full Day Architectural Treasures of Hanoi by Car (L)$imp128$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-FD-05', 'Hanoi: Cooking & Traditions in Duong Lam Village (L)', $imp129$Hanoi: Cooking & Traditions in Duong Lam Village (L) It is best to start earlier today so as to enjoy the coolest and qu$imp129$, 'Full Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp130$**Hanoi: Cooking ****&**** Traditions in Duong Lam Village (L)** Duong Lam's ancient village atmosphere and culinary traditions make it one of day-trip Hanoi's most rewarding destinations, and this refined full-day version distils the experience to its essence. A private vehicle transports guests from the city in comfort, arriving at the village in the quiet of the mid-morning when tourist numbers are minimal and the village returns to its own unhurried rhythm. A family household opens its kitch$imp130$, $imp131$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Cooking & Traditions in Duong Lam Village (L)$imp131$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAN-FD-06', 'Hanoi: Full Day City Highlights (L) *Military Historical focussed', $imp132$Hanoi: Full Day City Highlights (L) *Military Historical focussed (~ 08:00 - 16:00) Your guide will discuss and agree on$imp132$, 'Full Day', 'Culinary', 'Hanoi', 'Easy & Comfortable', $imp133$For the historically minded traveller, Hanoi holds a military and political history of extraordinary complexity and drama, and this full-day journey — designed specifically around that lens — reveals the capital as one of the twentieth century's most consequential cities. A specialist guide with military history expertise leads a circuit encompassing the Vietnam Military History Museum and its remarkable collection of captured weaponry and aircraft, the Hoa Lo Prison where American pilots were h$imp133$, $imp134$In-depth military history access — context, stories, and sites beyond the guidebook · Hanoi: 1,000 years of history, culture, and flavour layered into every street · Hanoi: Full Day City Highlights (L) *Military Historical focussed$imp134$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAL-SEA-HD-01', 'Halong Bay Seaplane Experience', 'Scenic seaplane | Karst photography | Sunrise/sunset flight', 'Half Day', 'Nature & Scenic', 'Halong Bay', 'Luxury', $imp135$To arrive at Halong Bay by seaplane is to experience one of the world's great landscapes in the most breathtaking manner imaginable — a low-altitude approach that transforms 1,600 limestone islands into a painting of surreal beauty spread across the emerald waters of the Gulf of Tonkin. The flight itself is an event of pure theatre: the city dissolving into rice paddies, the coast approaching, and then the sudden revelation of the bay in its full, impossible grandeur. The pilot circles over the $imp135$, $imp136$Bird's-eye view of UNESCO karst landscape — impossible from any boat on the bay · Only 25 minutes but entirely transformative — one of Vietnam's defining experiences · Best combined with Heritage Line cruise for ultimate sky-and-sea arrival$imp136$, 'From $200/person', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAL-CRU-2D1N-01', 'Halong Bay Cruise (2 Days 1 Night)', 'UNESCO cruise | Cave exploration | Kayaking | Seafood | Squid fishing', '2 Days 1 Night', 'Nature & Cruise', 'Halong Bay', 'Premium', $imp137$**Day 1 — Arrival on the Bay** Boarding your private junk at the Tuan Chau Marina, you leave the mainland behind with a glass of welcome champagne as the limestone towers of Halong Bay rise around the bow. The afternoon is devoted to the bay's most celebrated landscapes: a private kayak excursion through an arched cave into a hidden emerald lagoon, a swim from a secluded beach accessible only by water, and the simple pleasure of watching the karst formations catch the changing afternoon light fr$imp137$, $imp138$UNESCO World Heritage Site — 1,600+ limestone karsts rising from jade-green waters · Sung Sot Cave — Vietnam's largest accessible cave, cathedral-scale chambers · Kayaking through hidden lagoons and authentic floating fishing villages$imp138$, 'Mid–Luxury', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-LHBA-CRU-2D1N-01', 'Lan Ha Bay Cruise — Cat Ba Island (2 Days 1 Night)', 'Lan Ha Bay | Cat Ba National Park | Rock climbing | Fishing villages | Kayak', '2 Days 1 Night', 'Nature & Adventure', 'Lan Ha Bay / Cat Ba', 'Premium', $imp139$**Day 1 — Cat Ba Island and the Bay Beyond** Lan Ha Bay — the southern extension of Halong Bay adjacent to Cat Ba Island — offers everything its more famous neighbour does, with the added grace of fewer vessels and a wilder, more intimate atmosphere. Your private cruise departs Cat Ba Town aboard a beautifully appointed vessel, threading immediately into a world of limestone pillars, floating fishing villages, and hidden beaches accessible only by boat. The afternoon programme combines kayaking $imp139$, $imp140$Far fewer tourists than Halong Bay — the same karst scenery, half the crowds · Cat Ba National Park — primary forest and the critically endangered Cat Ba langur · Authentic floating fishing villages where families have lived for generations$imp140$, 'Mid–Premium', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAL-LUX-3D2N-01', 'Halong Bay Premium Cruise (3 Days 2 Nights)', 'Heritage Line | Luxury cruise | Exclusive routes | Cooking class | Tai Chi', '3 Days 2 Nights', 'Luxury Cruise', 'Halong Bay', 'Ultra Luxury', $imp141$**Day 1 — The Bay Revealed** The finest Halong Bay experience begins from the dock — the moment your private luxury vessel pulls away from the marina and the limestone world closes in around you with theatrical grandeur. This is no ordinary cruise: the vessel is selected for its exceptional comfort, its chef's credentials, and its captain's knowledge of the bay's less-travelled corridors. The first afternoon establishes the rhythm: a languid lunch on the sundeck, a private kayaking excursion int$imp141$, $imp142$Heritage Line Ginger — only 20 cabins, museum-quality Vietnamese art on board · Exclusive routes entirely away from mass tourism zones of the main bay · Tai Chi at sunrise on the private top deck — Halong at its most serene$imp142$, 'Luxury–Ultra Luxury', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-NBI-HD-01', 'Ninh Binh: Private Transfer to Halong Bay', $imp143$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp143$, 'Half Day', 'Nature', 'Ninh Binh', 'Easy & Comfortable', $imp144$The journey from Ninh Binh to Halong Bay cuts through some of northern Vietnam's most quietly beautiful landscapes, and this private transfer is designed to make the most of every kilometre. A comfortable vehicle and an informed guide transform what might be a utilitarian transfer into a genuine extension of the journey, with stops at vantage points above the Red River Delta, visits to roadside markets selling produce from nearby farms, and a narrated overview of the historical significance of t$imp144$, $imp145$Private transfer with specialist guide — seamless logistics combined with local insight · Trang An UNESCO waterways — ancient royal capital ringed by karst peaks and cave systems · After breakfast set off on your journey to Halong Bay. This is a long$imp145$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-NBI-HD-02', 'Ninh Binh: Mai Chau to Van Long Nature Reserve', $imp146$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp146$, 'Half Day', 'Adventure', 'Ninh Binh', 'Easy & Comfortable', $imp147$The Van Long Nature Reserve is among northern Vietnam's most pristine wetland environments — a vast, still body of water enclosed by limestone cliffs and populated by rare langurs, water birds, and the reflected silhouettes of karst formations that rival anything in Halong Bay for sheer visual drama. This private half-day excursion travels from Mai Chau through the hill scenery of Hoa Binh Province to arrive at the reserve for a rowing boat excursion conducted in near-total silence, the better t$imp147$, $imp148$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Trang An UNESCO waterways — ancient royal capital ringed by karst peaks and cave systems · Ninh Binh: Mai Chau to Van Long Nature Reserve$imp148$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-NBI-FD-01', $imp149$Ninh Binh: 'Free and Easy' Ninh Binh Adventure Day (S,L)$imp149$, $imp150$Standard: Local trek/trail bicycles  Downgrade options: text  Surcharged upgrade options on request: Arrange for trek/tr$imp150$, 'Full Day', 'Cycling', 'Ninh Binh', 'Easy & Comfortable', $imp151$Ninh Binh demands to be experienced freely, at exactly the pace its landscape imposes — the pace of a rowing boat on the Ngo Dong River, of a bicycle on a dike road beside the rice paddies, and of a walker approaching the great pagoda of Bai Dinh through a forest of frangipani trees. This 'free and easy' full day provides a private guide, comfortable transport, and a loosely structured itinerary that leaves ample room for spontaneity: an unplanned stop at a roadside lotus pond, a conversation wi$imp151$, $imp152$Private specialist guide — exclusive access, authentic depth, unhurried discovery · Trang An UNESCO waterways — ancient royal capital ringed by karst peaks and cave systems · Ninh Binh: 'Free and Easy' Ninh Binh Adventure Day (S,L)$imp152$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-NBI-2D-01', 'Ninh Binh 2D1N Nature, Caves and Waterways to Hanoi', $imp153$Standard: Local trek/trail bicycles  Downgrade options: "Cuc Phuong is proactive in conservation efforts and you may wis$imp153$, '2 Days 1 Night', 'Cycling', 'Ninh Binh', 'Easy & Comfortable', $imp154$**Day 1 — Waterways and Caves** Ninh Binh announces itself with drama: limestone karsts rising vertically from the flat paddy fields of the delta, creating a landscape often described as Halong Bay on land — and the comparison, while reductive, captures something of the visual shock. The first day is devoted to the waterways that make this landscape most accessible: a private rowing boat excursion through the cave system at Trang An, where the river ducks beneath limestone arches into chambers o$imp154$, $imp155$Underground world of extraordinary geological scale — one of earth's great natural cathedrals · Trang An UNESCO waterways — ancient royal capital ringed by karst peaks and cave systems · Ninh Binh 2D1N Nature, Caves and Waterways to Hanoi$imp155$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-NBI-2D-02', 'Cuc Phuong National Park - One Day Trekking (L)', $imp156$Standard: Local trek/trail bicycles  Downgrade options: text  Surcharged upgrade options on request: Arrange for trek/tr$imp156$, '2 Days 1 Night', 'Adventure', 'Ninh Binh', 'Moderate', $imp157$**Day 1 — Into the National Park** Cuc Phuong National Park holds the distinction of being Vietnam's oldest protected forest, and a full day within its ancient trees feels like a journey into a world that preceded human history entirely. A private naturalist guide leads a trek through primary forest where the canopy closes sixty metres overhead and the undergrowth is alive with the movement of civets, giant squirrels, and the rare clouded leopard whose prints occasionally appear on trail mud. Th$imp157$, $imp158$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · Trang An UNESCO waterways — ancient royal capital ringed by karst peaks and cave systems · Cuc Phuong National Park - One Day Trekking (L)$imp158$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-NBI-3D-01', 'Ninh Binh 3D2N Nature, Caves and Waterways to Airport', $imp159$Standard: Local trek/trail bicycles The guests can start at 8 am and have the afternoon in Tam Coc at leisure, or start $imp159$, '3 Days 2 Nights', 'Cycling', 'Ninh Binh', 'Easy & Comfortable', $imp160$**Day 1 — First Encounter with the Karsts** The journey from Hanoi south into Ninh Binh Province is itself a transition — from the urban intensity of the capital into a landscape of increasing quiet and beauty, where the limestone towers that characterise the region begin to appear above the rice fields like sentinels announcing a different world. A private guide meets guests at their Hanoi hotel and narrates the drive south with commentary on the agricultural landscape and its seasonal rhythms.$imp160$, $imp161$Underground world of extraordinary geological scale — one of earth's great natural cathedrals · Trang An UNESCO waterways — ancient royal capital ringed by karst peaks and cave systems · Ninh Binh 3D2N Nature, Caves and Waterways to Airport$imp161$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-01', $imp162$Sapa: Waterfalls & Heaven's Gate (S)$imp162$, $imp163$Standard: Snacks on treks: We like to provide a few snacks a day when on our treks/walks. Example: fresh fruits, an asso$imp163$, 'Half Day', 'Nature', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp164$**Sapa: Waterfalls ****&**** Heaven's Gate (S)** Heaven's Gate — the high mountain pass known as O Quy Ho — stands at nearly 2,000 metres above sea level and commands a view of the Muong Hoa Valley that stops most visitors completely still with its scale and beauty. This private half-day excursion follows the mountain road to its summit, pausing at Silver Waterfall and Love Waterfall en route — two dramatic cascades whose roar can be heard long before they appear through the pine forest. At the $imp164$, $imp165$Private specialist guide — exclusive access, authentic depth, unhurried discovery · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Arrive at Silver Waterfall where you can enjoy the stunning views of the s$imp165$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-02', 'Sapa: Light Trek Through Valley & Rice Fields (S)', $imp166$Standard: Snacks and water with treks  Downgrade options: text  Surcharged upgrade options on request: text$imp166$, 'Half Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp167$**Sapa: Light Trek Through Valley ****&**** Rice Fields (S)** The valleys below Sapa were sculpted by minority communities over centuries into some of the world's most breathtaking agricultural landscapes — rice terraces that cascade from the mountaintops to the valley floor in perfectly graduated curves that shift from emerald to gold with the seasons. This private light trekking excursion descends from the town through the most photogenic sections of the Muong Hoa Valley, accompanied by a loca$imp167$, $imp168$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Light Trek Through Valley & Rice Fields (S)$imp168$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-03', 'Sapa: 2 Hour Nam Cang Village Walk', $imp169$Standard: Staying at Topas Riverside Lodge  Downgrade options: text  Surcharged upgrade options on request: If staying a$imp169$, 'Half Day', 'Nature', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp170$Nam Cang is a hill tribe village of remarkable tranquillity and authentic character, sitting above the valley in a bowl of mountains where the morning mist lingers longest and the sound of traditional instruments carries clearly on the mountain air. This private two-hour walk follows a trail through pine forest and open meadow, descending into the village at the hour when the daily rhythm is most visible — women returning from their hillside gardens, children gathered at the communal water point$imp170$, $imp171$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Explore Nam Cang village on foot in the early morning to learn more$imp171$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-04', $imp172$Sapa: Private Lunch with Tinh's Family (L)$imp172$, $imp173$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp173$, 'Half Day', 'Nature', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp174$Among the most intimate and culturally resonant experiences in Sapa is an invitation to eat with a local family, and this private lunch with Tinh and his family delivers exactly that — a meal that is simultaneously delicious, educational, and genuinely moving. Tinh's family home, set in the hills above the Muong Hoa Valley with views that belong in a painting, has welcomed guests for years with a hospitality that feels entirely unperformed. The lunch table features a selection of dishes prepared$imp174$, $imp175$Thoughtfully designed for families — engaging, educational, genuinely fun for all ages · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Private Lunch with Tinh's Family (L)$imp175$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-05', $imp176$Sapa: Waterfalls & Heaven's Gate (S,L)$imp176$, $imp177$Standard: Snacks on treks: We like to provide a few snacks a day when on our treks/walks. Example: fresh fruits, an asso$imp177$, 'Half Day', 'Nature', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp178$**Sapa: Waterfalls ****&**** Heaven's Gate (S,L)** This extended version of the Heaven's Gate excursion adds a batik art workshop that perfectly complements the morning's visual richness with a hands-on creative experience rooted in the same H'mong cultural tradition that produced the landscape's most distinctive textiles. The morning follows the mountain road to Silver Waterfall, Love Waterfall, and the summit viewpoint at O Quy Ho, with the guide providing continuous narrative about the geolog$imp178$, $imp179$Private specialist guide — exclusive access, authentic depth, unhurried discovery · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Arrive at Silver Waterfall where you can enjoy the stunning views of the s$imp179$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-06', 'Sapa: Sin Chai to Nam Cang Village Trek (L)', $imp180$Standard: Snacks and water with treks Topas Ecolodge 45 minutes car transfer to Sin Chai Village +  Sapa: Sin Chai to Na$imp180$, 'Half Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp181$The trek from Sin Chai village to Nam Cang crosses some of the Muong Hoa Valley's most varied and visually rewarding terrain, passing from the H'mong hamlets that cling to the valley's upper slopes into the more sheltered world of the valley floor, where water buffalo graze between rice paddies and wooden bridges arc over rushing streams. A private guide who knows every family along the route personalises the experience with introductions and context that transform individual encounters into gen$imp181$, $imp182$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Sin Chai to Nam Cang Village Trek (L)$imp182$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-HD-07', $imp183$Sapa: Waterfalls & Heaven's Gate & Batik Art (S,L)$imp183$, $imp184$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp184$, 'Half Day', 'Adventure', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp185$**Sapa: Waterfalls ****&**** Heaven's Gate ****&**** Batik Art (S,L)** Heaven's Gate and the Silver and Love Waterfalls form the most dramatic natural circuit above Sapa, and this private excursion adds a batik art experience that makes the half-day feel complete in both its outdoor and cultural dimensions. The morning's drive along the mountain road to O Quy Ho is narrated by a knowledgeable guide whose knowledge of the valley's minority communities brings context to the extraordinary landscape$imp185$, $imp186$Master artisan access — hands-on participation in a living cultural tradition · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Waterfalls & Heaven's Gate & Batik Art (S,L)$imp186$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-01', 'Sapa: A Day Bac Ha Sunday Market (L)', $imp187$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp187$, 'Full Day', 'Culinary', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp188$The Bac Ha Sunday market is among the most flamboyant and authentic minority markets in all of northern Vietnam — a weekly gathering that draws Flower H'mong women from a dozen surrounding villages in costumes of such extraordinary colour and complexity that the entire marketplace becomes a living textile museum. A private full-day excursion from Sapa makes the journey worthwhile, descending from the mountains into a different valley where the Saturday night arrival of traders from the hills cre$imp188$, $imp189$Private specialist guide — exclusive access, authentic depth, unhurried discovery · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Your guide and driver will return you to your hotel.$imp189$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-02', 'Sapa: Morning Private Lao Cai Train Station Transfer (to Sapa) with Guide', $imp190$Sapa: Morning Private Lao Cai Train Station Transfer (to Sapa) with Guide Your guide will meet you outside the exit door$imp190$, 'Full Day', 'Nature', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp191$The overnight train from Hanoi to Lao Cai is an experience in itself — the private cabin's rhythmic passage through the night, arriving at the mountain station as dawn breaks over the valley below Sapa — and this private morning transfer ensures that the transition from train to mountain is as seamless and comfortable as possible. A dedicated vehicle and guide meet guests on the platform, handling luggage with efficiency and narrating the 35-kilometre ascent to Sapa with observations about the c$imp191$, $imp192$Private transfer with specialist guide — seamless logistics combined with local insight · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Morning Private Lao Cai Train Station Transfer (to Sapa) with $imp192$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-03', 'Sapa: Light Trek Through Valley & Rice Fields with Batik Art (S)', $imp193$Sapa: Light Trek Through Valley & Rice Fields with Batik Art (S) After a short road transfer to Y Linh Ho, begin your de$imp193$, 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp194$**Sapa: Light Trek Through Valley ****&**** Rice Fields with Batik Art (S)** The light trek through the Muong Hoa Valley, extended to include a full day and enriched with a batik art workshop in a village home, represents the Sapa experience at its most complete and satisfying. Morning descends from town through terraced rice fields at their most photogenic — catching the mist as it lifts or the afternoon gold as it settles, depending on the season — with a private guide providing commentary on $imp194$, $imp195$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Light Trek Through Valley & Rice Fields with Batik Art (S)$imp195$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-04', 'Sapa: Private Train Station Transfer (to Lao Cai Train Station) with Guide (D)', $imp196$Sapa: Private Train Station Transfer (to Lao Cai Train Station) with Guide (D) Your guide will ensure that you arrive in$imp196$, 'Full Day', 'Nature', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp197$The descent from Sapa to Lao Cai for the overnight train is a journey that deserves to be made slowly, and this private transfer is designed to honour that impulse. A guide accompanies guests on a route that pauses for final views of the Muong Hoa Valley from the mountain road, stops at a minority village where the morning market is still active, and arrives at the station with time to absorb the river-town atmosphere of Lao Cai before boarding. The guide's knowledge of the station and its proto$imp197$, $imp198$Private transfer with specialist guide — seamless logistics combined with local insight · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Private Train Station Transfer (to Lao Cai Train Station) with$imp198$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-05', 'Sapa: Trek Through Valley & Rice Fields with Batik Art (L)', 'duplicated', 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp199$**Sapa: Trek Through Valley ****&**** Rice Fields with Batik Art (L)** The trek through the Muong Hoa Valley, undertaken at full-day pace with a skilled private guide and concluded with an afternoon batik workshop, delivers the quintessential Sapa experience in a single deeply satisfying arc. The morning trail descends through an escalating series of views — rice terraces, mountain silhouettes, waterfalls, and the intimate details of village life — at a pace determined by curiosity and comfort r$imp199$, $imp200$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Trek Through Valley & Rice Fields with Batik Art (L)$imp200$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-06', 'Sapa: Morning/Afternoon Lech Village Trek', 'No lunch in the afternoon', 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp201$The Lech village trek is among Sapa's quietest and most meditative walking experiences, following a trail that ascends through cloud forest to a settlement so remote and self-contained that the twenty-first century seems not yet to have made its presence fully felt. A private guide with deep community relationships ensures that the village welcome is genuine and the encounter respectful, with time spent in conversation with the elders, observation of the weaving and farming work that structures $imp201$, $imp202$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Morning/Afternoon Lech Village Trek$imp202$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-07', 'Sapa: 7km Trek with  H Mong Village & Waterfalls (Medium to Hard Level)', $imp203$Winter, dried season, cool and not wet every 15-16 cc day time. Night time is around 8-10 cold. Hard Level (1.200m Eleva$imp203$, 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp204$**Sapa: 7km Trek with  H Mong Village ****&**** Waterfalls (Medium to Hard Level)** A seven-kilometre trek through the Muong Hoa Valley, incorporating a visit to an H'mong village and culminating at a pair of cascading waterfalls, delivers Sapa's most essential rewards within a single moderately challenging but deeply rewarding day. The trail demands reasonable fitness and good footwear, but it never asks more of the walker than the landscape more than compensates for — at every point of effort,$imp204$, $imp205$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: 7km Trek with  H Mong Village & Waterfalls (Medium to Hard Le$imp205$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-08', 'Sapa: Ta Van - Giang Ta Chai - Su Pan with Batik Art', $imp206$Fitness level: medium to hard Approx. 8km/ 5 hrs walking Batik Art: 1.5 hrs Elevation summary: Between 1100- 1300 m with$imp206$, 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Easy & Comfortable', $imp207$The circuit from Ta Van through Giang Ta Chai to Su Pan village covers some of the Muong Hoa Valley's most diverse terrain and most rewarding minority community encounters, crossing the Muong Hoa stream on bamboo bridges, traversing paddy dike paths that require the balance of long experience, and ascending to viewpoints that justify every step. A private guide with deep relationships throughout these villages personalises every stop — pausing to introduce a silversmith whose work adorns the cos$imp207$, $imp208$Master artisan access — hands-on participation in a living cultural tradition · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Ta Van - Giang Ta Chai - Su Pan with Batik Art$imp208$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-09', 'Sapa: Sin Chai to Nam Cang Village Trek', $imp209$Estimated time on road transfer(s): 45 mins from Topas Ecolodge to Sin Chai, 1.5hrs from Nam Cang to Topas Ecolodge Trek$imp209$, 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp210$The full-day trek from Sin Chai to Nam Cang village is Sapa's most comprehensive walking day — a circuit that moves through four distinct landscape types (mountain forest, open hillside, paddy valley, and riverside trail) and visits communities representing two different minority ethnic groups within a single continuous journey. A private guide with relationships on both sides of the valley provides the cultural navigation that transforms geographical movement into genuine human encounter, facil$imp210$, $imp211$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Your half day trek will begin near Sin Chai village deeper within t$imp211$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-FD-10', 'Sapa: Trek with  H Mong Village & Waterfalls', $imp212$Hard Level (1.200m Elevation). This trek is away from typical routes and waterfalls.$imp212$, 'Full Day', 'Adventure', 'Sapa & Lao Cai', 'Moderate', $imp213$**Sapa: Trek with  H Mong Village ****&**** Waterfalls** A full-day trek through the Muong Hoa Valley, visiting an H'mong village and reaching a pair of waterfalls whose volume and drama increase with the season, is Sapa's most straightforward yet most rewarding walking day — the one that delivers the complete mountain experience without unnecessary complexity. A private guide whose family has farmed these terraces for generations provides continuous commentary that is simultaneously ecological,$imp213$, $imp214$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · H'mong highland heartland — Southeast Asia's most spectacular terraced mountain landscape · Sapa: Trek with  H Mong Village & Waterfalls$imp214$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-ADV-FD-01', 'Fansipan Summit — Cable Car Day (Full Day)', 'Fansipan summit | Cable car world record | Highest peak Indochina | Alpine flora', 'Full Day', 'Adventure', 'Sapa / Fansipan', 'Premium', $imp215$Fansipan is Indochina's highest peak — the Roof of Southeast Asia, as its admirers know it — and riding the world's longest cable car to its 3,143-metre summit is one of Vietnam's most dramatically experiential days. The ascent through cloud — the valley floor dissolving in mist, the forest canopy flattening below, the rocky summit emerging from the vapour — is an experience that rewards the early start required to beat the morning cloud build-up. At the summit, the views on clear days extend ac$imp215$, $imp216$Roof of Indochina — the highest peak in Vietnam, Laos, and Cambodia (3,143m) · World's longest single-wire cable car — a record-breaking engineering feat through cloud forest · Summit Buddhist temple structures and rare alpine flora — a world apart f$imp216$, 'Mid–Premium', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-TRK-3D2N-01', 'Sapa Trekking — Muong Hoa Valley (3 Days 2 Nights)', $imp217$H'mong village trek | Rice terraces | Ta Van | Giang Ta Chai | Sapa Sisters$imp217$, '3 Days 2 Nights', 'Adventure & Culture', 'Sapa', 'Premium', $imp218$**Day 1 — Into the Valley** The trekking journey into the Muong Hoa Valley begins where the road ends — at the point where the trail descends into a landscape that belongs entirely to the mountains and the communities that have shaped it over centuries. The first day's walk establishes the rhythm that will define the experience: slow enough to absorb the terraced agriculture on both sides of the valley, responsive enough to pause for the conversations that arise naturally when a knowledgeable gu$imp218$, $imp219$Golden harvest season (Sep–Nov) — world-class rice terrace photography, globally recognised · H'mong and Red Dao village immersion — genuine community welcome, not a performance · Sapa Sisters option: ALL guides are local H'mong women — proceeds dire$imp219$, '$200–$400/person', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-SPA-LUX-4D3N-01', 'Sapa Luxury Retreat (4 Days 3 Nights)', 'Topas Ecolodge | Infinity pool | Private trekking | Spa | Cultural performances', '4 Days 3 Nights', 'Luxury & Wellness', 'Sapa', 'Ultra Luxury', $imp220$**Day 1 — Arrival in the Clouds** The approach to Sapa by private vehicle from Lao Cai delivers a series of increasingly dramatic mountain views culminating in the town's own arrival above the cloud line — an entrance of considerable theatrical power. A private guide meets guests at the station or airport transfer point and provides context throughout the ascent. Accommodation is at one of the valley's finest properties — a lodge or boutique hotel selected for its views, its spa facilities, and $imp220$, $imp221$Topas Ecolodge — Asia's most iconic eco-luxury mountain lodge, infinity pool at 1,800m · Completely private trekking routes away from all group tourism trails · Hotel de la Coupole MGallery alternative — Art Deco luxury in the heart of Sapa Town$imp221$, '$500–$1,200/person', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-01', 'Mai Chau: Private Dining By the Waterfall at the Avana Retreat', 'Staying at Avana - through Avana', 'Half Day', 'Nature', 'Mai Chau', 'Easy & Comfortable', $imp222$The Avana Retreat sits in the Mai Chau valley in a state of such utter natural grace that dining beside its waterfall feels less like a restaurant experience and more like a private audience with the landscape itself. This exclusive private dining arrangement positions guests at a table suspended above the cascade, where the sound of falling water and the sight of the surrounding mountains create a setting that no urban restaurant can approach for sheer experiential power. The menu draws from th$imp222$, $imp223$World-class wellness immersion in Vietnam's most serene and pristine setting · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Mai Chau: Private Dining By the Waterfall at the Avana Retreat$imp223$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-02', 'Mai Chau: Private Jeep Adventure', $imp224$Need our guide to go along. The Avana staff's English isn't good enough yet.$imp224$, 'Half Day', 'Adventure', 'Mai Chau', 'Easy & Comfortable', $imp225$The Mai Chau valley, with its patchwork of rice fields, limestone outcrops, and White Thai stilt houses set against forested hills, is best explored by the vehicle that has navigated these roads since the American War era — the vintage military jeep, which lends every outing a spirit of authentic adventure that softer transport cannot replicate. This private jeep excursion carves a circuit through the valley's most compelling terrain, stopping at White Thai villages where traditional weaving is $imp225$, $imp226$Private vintage Jeep — off-schedule, entirely personal, military history depth · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Feel the freedom of the wind blowing in your hair as you take a tour in$imp226$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-03', 'Mai Chau: Mai Chau Arrival & Trekking Xa Linh to Hang Kia (L)', 'Route: Hanoi - Lac Village (Mai Chau) - Xa Linh - Hang Kia', 'Half Day', 'Culinary', 'Mai Chau', 'Moderate', $imp227$**Mai Chau: Mai Chau Arrival ****&**** Trekking Xa Linh to Hang Kia (L)** The trek from Xa Linh to Hang Kia village crosses a section of the Mai Chau highlands that few itineraries include and fewer still explore with the depth that a private guide makes possible. The trail begins in the White Thai lowlands and ascends gradually into the territory of the H'mong communities who have farmed the upper slopes since long before recorded history, offering a journey through two distinct cultural worlds$imp227$, $imp228$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Mai Chau: Mai Chau Arrival & Trekking Xa Linh to Hang Kia (L)$imp228$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-04', 'Mai Chau: Trekking Hang Kia to Xam Khoe Village (L)', $imp229$Route: Hang Kia - Cun Kheo Village - Van Village - Bang Village - Buoc Village - Muoi Village - Xam Khoe Village - Mai C$imp229$, 'Half Day', 'Adventure', 'Mai Chau', 'Moderate', $imp230$The trek from Hang Kia village to Xam Khoe follows a high mountain trail that opens into views of the surrounding valleys unavailable from any road, and the journey between two culturally distinct communities makes the walking feel purposeful in a way that circular routes often cannot achieve. The morning begins in Hang Kia's H'mong atmosphere — the elaborately embroidered clothing of the women, the sound of traditional music from a communal house — before the trail ascends to a ridge offering a$imp230$, $imp231$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Mai Chau: Trekking Hang Kia to Xam Khoe Village (L)$imp231$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-05', 'Mai Chau: Cycle Mai Chau Ecolodge to Pom Coong Village (L)', $imp232$Route: Mai Chau Ecolodge - Lac Village - Pom Coong Village - Noi Bai Airport/Hanoi$imp232$, 'Half Day', 'Cycling', 'Mai Chau', 'Easy & Comfortable', $imp233$The Mai Chau Ecolodge sits in the valley at a point where the White Thai village of Pom Coong is visible across the rice fields — close enough to cycle to in twenty leisurely minutes along dike paths that trace the paddy's edge with geometric precision. This private cycling excursion begins at the lodge's own fleet of well-maintained bicycles and follows a curated route that enters the village at its most atmospheric hour, when the morning work is underway and the community's daily life is fully$imp233$, $imp234$Private specialist guide — exclusive access, authentic depth, unhurried discovery · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Mai Chau: Cycle Mai Chau Ecolodge to Pom Coong Village (L)$imp234$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-06', 'Mai Chau: Xa Linh to Hang Kia Easy Trek (L)', 'Staying in Mai Chau', 'Half Day', 'Culinary', 'Mai Chau', 'Moderate', $imp235$The easy morning walk from Xa Linh to Hang Kia is designed for guests who want the Mai Chau highland experience without committing to a strenuous day — a gentle trail through diverse landscape that delivers cultural richness and visual beauty without requiring exceptional fitness or time. The route passes through White Thai farmland before ascending gradually through secondary forest to the H'mong village of Hang Kia, where the change in architecture, dress, and agricultural practice is immediat$imp235$, $imp236$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Mai Chau: Xa Linh to Hang Kia Easy Trek (L)$imp236$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-HD-07', 'Mai Chau: Mai Chau Local Culture (L)', 'Staying at Avana - through ICT', 'Half Day', 'Cultural', 'Mai Chau', 'Easy & Comfortable', $imp237$To spend a half-day with a White Thai family in Mai Chau is to enter a world of extraordinary hospitality and cultural depth that the valley's beauty makes all the more compelling as a setting. A private guide selects a family home known for its warmth of welcome and the authenticity of its cultural practice, and the visit unfolds according to the household's own rhythm — perhaps joining the women at their weaving looms, watching the preparation of a traditional meal using locally grown ingredie$imp237$, $imp238$Private specialist guide — exclusive access, authentic depth, unhurried discovery · White Thai cultural valley — tranquil, undiscovered, among Vietnam's finest slow-travel escapes · Your half day exploring local villages with your guide is flexible, $imp238$, '', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-MCC-PHO-3D2N-01', 'Mu Cang Chai — Rice Terrace Photography (3 Days 2 Nights)', $imp239$Golden harvest | Rice terrace photography | H'mong culture | Specialist guide$imp239$, '3 Days 2 Nights', 'Photography & Nature', 'Mu Cang Chai', 'Premium', $imp240$**Day 1 — The Terraces at Golden Hour** Mu Cang Chai's rice terraces are among the most photographically extraordinary landscapes on earth — a vast staircase of water and grain descending from the peaks above Yen Bai Province in curves of such mathematical precision and natural grace that the effect, at harvest season, is of a landscape painted entirely in gold. The journey from Hanoi or Nghia Lo is long and rewarding in equal measure, the mountain road ascending through scenery that prepares th$imp240$, $imp241$Asia's finest rice terrace photography — a landscape recognised globally as extraordinary · Golden harvest window: late September to mid-October ONLY — this cannot be replicated · Specialist local photography guide with viewpoint knowledge far beyond$imp241$, '$200–$400/person (excl. accommodation)', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-HAG-JEP-4D3N-01', 'Ha Giang Loop — Private Jeep (4 Days 3 Nights)', 'Ma Pi Leng Pass | Dong Van Geopark | Private Jeep | Ethnic minorities | Lung Cu', '4 Days 3 Nights', 'Adventure & Scenic Drive', 'Ha Giang', 'Premium', $imp242$**Day 1 — The Gate of the North** Ha Giang Province begins where the map of ordinary Vietnam ends — a landscape of such geological drama and cultural distinctiveness that the journey north from Ha Giang city feels less like travel and more like a passage into another world entirely. The private jeep departs the provincial capital and begins its ascent into the Dong Van Karst Plateau Geopark — a UNESCO-recognised landscape of towering limestone formations, precipitous valleys, and minority villag$imp242$, $imp243$Vietnam's most spectacular mountain road — Ma Pi Leng Pass, canyon above turquoise Nho Que River · Dong Van UNESCO Geopark — geology and landscape on a mythological scale · Lung Cu Flag Tower — Vietnam's northernmost point on the China border$imp243$, '$150–$250/day private Jeep', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-BBC-NAT-2D1N-01', 'Ba Be Lake & National Park (2 Days 1 Night)', $imp244$Largest freshwater lake | Tay homestay | Puong Cave | Dau Dang Waterfall | Wildlife$imp244$, '2 Days 1 Night', 'Nature & Community', 'Ba Be / Bac Kan', 'Mid–Premium', $imp245$**Ba Be Lake ****&**** National Park (2 Days 1 Night)** **Day 1 — The Hidden Lake** Ba Be Lake is one of Southeast Asia's largest natural freshwater lakes, set within a national park of ancient forest, limestone caves, and the river system that feeds it — a landscape of such peaceful grandeur that arrival feels like the discovery of a world that tourism has touched but not yet diminished. The journey from Hanoi is long and rewarding, passing through the scenery of Bac Kan Province before arrivin$imp245$, $imp246$Vietnam's largest freshwater lake — almost entirely unknown to international visitors · Puong Cave — bat colony of extraordinary scale, limestone chambers of cathedral proportion · Tay minority stilt-house homestay — genuine community welcome, lakesi$imp246$, '$100–$150/person', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-NV-CAO-NAT-2D1N-01', 'Cao Bang — Ban Gioc Waterfall (2 Days 1 Night)', 'Ban Gioc largest waterfall | Bamboo raft | Nguom Ngao Cave | Pac Bo | Border', '2 Days 1 Night', 'Nature & History', 'Cao Bang', 'Mid', $imp247$**Day 1 — The Road to Ban Gioc** Cao Bang Province is the wild north's most extravagant secret — a borderland of dramatic scenery, Tay and Nung minority culture, and the revolutionary history that gives the landscape its additional layer of significance. The journey from Hanoi or Ha Giang is long and entirely worthwhile, the road revealing increasingly dramatic terrain as it approaches the Chinese border. Arrival at Ban Gioc Waterfall — the most impressive cataract in Vietnam and one of the larg$imp247$, $imp248$Ban Gioc — largest waterfall in SE Asia, straddling the Vietnam–China border · Bamboo raft approach to the base of the main cascade — perspective of extraordinary drama · Nguom Ngao Cave — spectacular stalactite chambers with almost no international $imp248$, '$100–$140/person', 'north') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-01', 'Hue: Private Airport Transfer to Airport with Guide', $imp249$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp249$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp250$The transition between airports and the landscapes that surround them rarely features in travellers' memories, but the journey from Hue's Phu Bai Airport to the city — when conducted with a knowledgeable private guide — becomes something more interesting than mere logistics. A dedicated guide meets arriving guests with a welcome that orientates them immediately to Hue's historical character: the significance of the Perfume River visible from the bridge, the citadel walls looming ahead, the relat$imp250$, $imp251$Private transfer with specialist guide — seamless logistics combined with local insight · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · *Private vehicle & driver = vehicle, driver, fuel, parking, toll fees,$imp251$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-02', 'Hue: Private Transfer from Hue to Hoi An (L)', $imp252$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp252$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp253$The mountain road between Hue and Hoi An crosses the Hai Van Pass — the 'Ocean Cloud Pass' — one of the most dramatically beautiful sections of road in all of Vietnam, and this private transfer devotes the time it deserves to a journey that many travellers cite as a highlight of the entire itinerary. The ascent through pine-forested slopes opens successively grander views of the coast to both north and south, culminating at the pass itself where French colonial fortifications and American-era bu$imp253$, $imp254$Private transfer with specialist guide — seamless logistics combined with local insight · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · *Private vehicle & driver = vehicle, driver, fuel, parking, toll fees,$imp254$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-03', 'Hue: Walking dinner with Guide (D)', $imp255$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp255$, 'Half Day', 'Wellness', 'Hue', 'Easy & Comfortable', $imp256$Hue's culinary tradition is among the most refined and distinctive in Vietnam — a royal court cuisine that elevated simple ingredients through extraordinary technique, and a street food culture that translated those same principles into the food of ordinary life. This private evening walk with a knowledgeable guide explores both worlds, beginning at the river market where vendors sell the city's most emblematic specialities — bánh khoái crispy pancakes, bún bò Hue's complex spiced broth, and nem$imp256$, $imp257$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Enjoy a relaxing meal sampling the delicious cuisine of Vietnam. Your$imp257$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-04', 'Hue: Morning DMZ with Cua Tung Beach (L)', $imp258$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp258$, 'Half Day', 'Adventure', 'Hue', 'Easy & Comfortable', $imp259$The Demilitarised Zone — the former border between North and South Vietnam that divided a nation for twenty years — lies just north of Hue, and a morning spent exploring its most significant sites alongside a private guide of genuine expertise produces one of the most emotionally and historically resonant experiences in all of Vietnam travel. The route visits the rebuilt Hien Luong Bridge over the Ben Hai River — the physical dividing line — and the Vinh Moc tunnels where an entire community liv$imp259$, $imp260$In-depth military history access — context, stories, and sites beyond the guidebook · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · With your guide spend the morning visiting the infamous DMZ, and the old H$imp260$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-05', 'Hue: Cruise on the Perfume River with Thien Mu Pagoda', $imp261$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp261$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp262$The Perfume River earns its name most completely in the early morning, when the water reflects the mist and the surrounding hills, and the boats that have plied these waters for centuries move with a grace that belongs to a pre-industrial world. This private cruise pairs the journey downriver with a visit to Thien Mu Pagoda — the seven-storey tower that has presided over Hue's river landscape since 1601 and remains the city's most immediately recognisable image. A private guide aboard the boat p$imp262$, $imp263$Private waterway journey — river scenery, local life, and timeless Vietnamese landscape · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Cruise on the Perfume River with Thien Mu Pagoda$imp263$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-06', 'Hue: Citadel (L)', $imp264$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp264$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp265$The Imperial Citadel of Hue is one of Southeast Asia's most magnificent royal complexes — a walled city within a city, modelled on Beijing's Forbidden City but expressing a distinctly Vietnamese aesthetic in its lacquerware pavilions, lotus ponds, and ceremonial gates whose colours have survived two centuries of tropical weather and wartime damage. A private guided visit to the citadel and its innermost sanctum — the Forbidden Purple City — goes well beyond the standard circuit, pausing at the r$imp265$, $imp266$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue's Citadel is comparatively modern in European terms, built over t$imp266$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-07', 'Phong Nha: Phong Nha to Hue Private Transfer with DMZ (L)', $imp267$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp267$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp268$The journey from Phong Nha to Hue by private vehicle, routed via the historic Ho Chi Minh Trail and the Demilitarised Zone, transforms what might be a simple transfer into a full-day experience of considerable historical depth and scenic richness. A private guide accompanies guests throughout, narrating the significance of the landscape — the cave systems used as field hospitals during the American War, the road itself as a marvel of logistical determination, and the DMZ as the physical manifest$imp268$, $imp269$Private transfer with specialist guide — seamless logistics combined with local insight · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · This morning you will have a private road trip this morning from Phong$imp269$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-08', 'Hue: Tha Om Ancient House (D)', $imp270$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp270$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp271$Tha Om Ancient House is one of the finest surviving examples of Hue's traditional aristocratic domestic architecture — a compound of dark timber, ceramic tile, and ancestral calm that speaks of a class of refined sensibility whose aesthetic instincts shaped the entire city. An evening visit, conducted in the quiet after the day's visitors have departed, allows a genuinely intimate encounter with the house and its current custodians — family members whose attachment to the building is not merely $imp271$, $imp272$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Your guide will take you to Tha Om Ancient House located in Kim Long Village$imp272$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-09', 'Hue: Half Day City Highlights (L)', $imp273$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp273$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp274$Hue's essential half-day circuit encompasses the experiences most emblematic of the imperial city's layered character — the citadel's great gates and ceremonial halls, the incense-thick atmosphere of a riverside pagoda, and the living street food culture that represents the court cuisine's democratic legacy. A private guide with deep Hue knowledge leads the morning at a pace shaped by curiosity rather than schedule, adapting the route to weather, current temple ceremonies, and the individual ent$imp274$, $imp275$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Your guide will meet you this afternoon, today you will take a boat trip on $imp275$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-10', 'Hue: Hue Royal Tombs (L)', $imp276$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp276$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp277$The royal tombs of Hue's Nguyen emperors are among the most varied and compelling funerary monuments in Asia — each one a complete architectural world expressing its patron's individual character with remarkable fidelity. Minh Mang's grand and symmetrical tomb reflects an emperor who prized order and Confucian propriety above all else; Tu Duc's elaborate garden complex speaks of a poet-emperor who built his mausoleum as a personal retreat for contemplation during his own lifetime; Khai Dinh's ec$imp277$, $imp278$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · With your guide visit the old capital city, a World Cultural Heritage$imp278$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-11', 'Hue: Citadel & Sunset at Thien Mu Pagoda (L or D)', $imp279$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp279$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp280$**Hue: Citadel ****&**** Sunset at Thien Mu Pagoda (L or D)** The great citadel of Hue at sunset is a sight of almost theatrical beauty — the ochre walls and vermilion gates catching the last horizontal light while the Perfume River below turns to bronze and the surrounding hills dissolve into silhouette. This private evening experience combines a guided visit to the citadel's most atmospheric interior spaces with a continuation to Thien Mu Pagoda, where the sunset light on the seven-storey towe$imp280$, $imp281$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Citadel & Sunset at Thien Mu Pagoda (L or D)$imp281$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-12', 'Hue: Historical & Picture Postcard Hue (D)', $imp282$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp282$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp283$**Hue: Historical ****&**** Picture Postcard Hue (D)** Hue's French colonial legacy interweaves with its imperial Vietnamese character in ways that produce an extraordinary and often overlooked architectural narrative, and this private half-day journey explores both with equal attention and expertise. The circuit moves between the European-influenced administration buildings of the new city and the Vietnamese vernacular splendour of the citadel and pagoda complexes, with a guide who understands $imp283$, $imp284$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Historical & Picture Postcard Hue (D)$imp284$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-13', 'Hue: An Introduction to Ancient Hue (L or D)', $imp285$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp285$, 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp286$An introduction to ancient Hue at the most refined scale — a private morning or afternoon that moves between the imperial city's most evocative sites at a pace shaped entirely by the guest's own curiosity and the guide's considerable knowledge. The itinerary typically encompasses Hue's most significant gates, the Forbidden Purple City at the citadel's heart, and one of the royal temples whose ceremonial atmosphere is most intact and most moving. A guide whose family has lived in Hue for generati$imp286$, $imp287$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: An Introduction to Ancient Hue (L or D)$imp287$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-14', 'Hue: Countryside Scooter & Tombs (L)', $imp288$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp288$, 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp289$**Hue: Countryside Scooter ****&**** Tombs (L)** The rural landscape around Hue — pine forests, farming villages, royal tomb compounds embedded in the hills, and the river winding through all of it — is best explored at scooter pace, which allows the journey between landmarks to be as interesting as the landmarks themselves. This private morning excursion by scooter visits two or three of the most characterful royal tomb complexes — selected by the guide for their current condition, their atmosp$imp289$, $imp290$Ground-level exploration by scooter — backstreet addresses no tour bus can navigate · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue is a historical location with strong cultural ties to its heritage and$imp290$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-15', 'Hue: Thien Vien Truc Lam Bach Ma Pagoda – Hoi An (L)', $imp291$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp291$, 'Half Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp292$The drive from Hue to Hoi An via the mountain retreat of Truc Lam Bach Ma Pagoda is among the most scenic and spiritually evocative of central Vietnam's day excursions — a journey that ascends into the cloud forest of Bach Ma National Park to visit a monastery of extraordinary serenity before descending to the coast and the ancient town of Hoi An. The pagoda, founded by a Buddhist master renowned throughout Vietnam, sits in a clearing of the cloud forest where the mist frequently obscures the su$imp292$, $imp293$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Thien Vien Truc Lam Bach Ma Pagoda – Hoi An (L)$imp293$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-16', 'Phong Nha: A Half Day on the Ho Chi Minh Trail & National Park (L)', $imp294$Phong Nha: A Half Day on the Ho Chi Minh Trail & National Park (L) The peanut fields area of the Ho Chi Minh original tr$imp294$, 'Half Day', 'Adventure', 'Hue', 'Easy & Comfortable', $imp295$**Phong Nha: A Half Day on the Ho Chi Minh Trail ****&**** National Park (L)** The Ho Chi Minh Trail — that extraordinary feat of military logistics that supplied the war in the south for over a decade — passes through some of Phong Nha's most dramatic terrain, and this private half-day traces a section of its route through what is now a UNESCO World Heritage protected national park of remarkable natural beauty. A private guide with specialist knowledge of the trail's history narrates the journe$imp295$, $imp296$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Phong Nha: A Half Day on the Ho Chi Minh Trail & National Park (L)$imp296$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-17', 'Hue: Evening Discovery Of Hue Speciality Cuisine By Cyclo', $imp297$Cyclo & taste the local food of Hue •        Meet your guide and rickshaw driver at your hotel around 6 pm.  •        En$imp297$, 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp298$As darkness settles over Hue and the evening trade begins on the streets flanking the citadel's south face, the most delicious way to discover the city's culinary character is by cyclo — that iconic three-wheeled pedicab that allows the passenger to sit forward at street level, receiving the aromas of the evening's cooking directly and without the mediation of glass or air conditioning. A private guide accompanies the cyclo on foot or by bicycle, narrating the culinary and architectural context $imp298$, $imp299$Vintage cyclo through the 36 ancient craft streets — Hanoi at its most intimate · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Evening Discovery Of Hue Speciality Cuisine By Cyclo$imp299$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-18', 'Hue: Cruise Perfume River & Lotus Flower Making', $imp300$Hue: Cruise Perfume River & Lotus Flower Making Meet your guide/driver at your hotel at 9am.$imp300$, 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp301$**Hue: Cruise Perfume River ****&**** Lotus Flower Making** The lotus flower holds a position of profound spiritual significance in Buddhist Vietnam that extends far beyond its role as a decorative motif — it is the flower of enlightenment, of purity rising from mud, of the Buddha's seat — and this private experience combines a Perfume River cruise with a hands-on introduction to the ancient art of lotus flower arrangement as practised in Hue's temple tradition. The morning cruise aboard a priva$imp301$, $imp302$Private waterway journey — river scenery, local life, and timeless Vietnamese landscape · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Cruise Perfume River & Lotus Flower Making$imp302$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-19', 'Hue: Cyclo Through the Imperial City and Thien Mu Pagoda', $imp303$Hue: Cyclo Through the Imperial City and Thien Mu Pagoda (~09:00 - 16:30) Through your guide's stories and insights imag$imp303$, 'Half Day', 'Cultural', 'Hue', 'Easy & Comfortable', $imp304$The combination of cyclo and private guided visit to the Imperial City creates one of Hue's most elegantly paced and visually rich half-day experiences — the cyclo providing the journey between sites at a speed that permits genuine observation, the citadel providing the destination that rewards every minute of travel to reach it. The route from the guesthouse or hotel follows the river road past the flag tower and the moat before entering the citadel through the great Ngo Mon Gate, whose ceremon$imp304$, $imp305$Vintage cyclo through the 36 ancient craft streets — Hanoi at its most intimate · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Cyclo Through the Imperial City and Thien Mu Pagoda$imp305$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-20', $imp306$Hue: Dinner at Princess Ngoc Son's Garden House$imp306$, $imp307$Hue: Dinner at Princess Ngoc Son's Garden House (~ 17:00 - 20:00) Embark on a journey through time as you meet Phan Thua$imp307$, 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp308$Princess Ngoc Son is one of Hue's most celebrated living connections to the imperial past — a descendant of the Nguyen dynasty who opens her family's extraordinary garden house to a small number of guests each evening for a dinner that is simultaneously a culinary experience of considerable refinement and a living history lesson of extraordinary intimacy. The house itself is a masterpiece of Hue's aristocratic domestic architecture — timber, tile, and garden in perfect equilibrium — and the dinn$imp308$, $imp309$Curated evening experience — the city at its most atmospheric and alive · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Dinner at Princess Ngoc Son's Garden House$imp309$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-21', 'Hue: Private Road Transfer to Hoi An with Guide & Lang Co Fisherman', 'Hue: Private Road Transfer to Hoi An with Guide & Lang Co Fisherman (~ 3.', 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp310$**Hue: Private Road Transfer to Hoi An with Guide ****&**** Lang Co Fisherman** The private road transfer from Hue to Hoi An is transformed by this itinerary from a necessary transit into one of the day's most memorable experiences — a journey that incorporates the stunning Hai Van Pass, a beach interlude at the crystalline waters of Lang Co, and the expertise of a guide who knows every viewpoint, every seafood restaurant, and every hidden detour that makes this coastal route one of the most sce$imp310$, $imp311$Private transfer with specialist guide — seamless logistics combined with local insight · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Lang Co Lagoon is very clean and a great source of fresh fish and seaf$imp311$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-22', 'Hue: Exclusive Private Dinner at the Imperial Citadel', $imp312$Hue: Exclusive Private Dinner at the Imperial Citadel (~ 18:00 start) During the Nguyen Dynasty, Hue was the capital of $imp312$, 'Half Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp313$A private dinner within the walls of the Imperial Citadel — in a setting that was closed to all but the emperor's court for over a century — is among the most exclusive experiences available in all of Vietnam. The tables are set within one of the citadel's restored ceremonial pavilions, surrounded by lantern light and the fragrant night air of the royal gardens, while a private team of chefs prepares a multi-course menu drawn from the imperial court cuisine tradition of the Nguyen dynasty. Each $imp313$, $imp314$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Exclusive Private Dinner at the Imperial Citadel$imp314$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-23', 'Hue: Exclusive Private Breakfast at the Imperial Citadel', $imp315$Hue: Exclusive Private Breakfast at the Imperial Citadel (~ 06:30 - 07:30) During the Nguyen Dynasty, Hue was the capita$imp315$, 'Half Day', 'Experience', 'Hue', 'Easy & Comfortable', $imp316$To take breakfast within the walls of the Imperial Citadel, as the early morning light falls on the vermilion pavilions and the lotus ponds before the day's visitors arrive, is an experience of refined, unhurried luxury that the historic setting makes extraordinary. A private team prepares a curated breakfast of Hue's most celebrated morning dishes — bánh cuốn rice rolls, bánh loc tapioca dumplings, chao rice congee with fresh herbs — served on lacquerware and ceramic chosen to reflect the aesth$imp316$, $imp317$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Exclusive Private Breakfast at the Imperial Citadel$imp317$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-24', 'Developments to work on:', 'Developments to work on:.', 'Half Day', 'Experience', 'Hue', 'Easy & Comfortable', $imp318$This curated Hue retreat experience is currently in development, combining the finest elements of the city's artistic and wellness traditions into a programme of exceptional depth and tranquillity. Please contact The Ant Adventures for details of current availability and bespoke design options tailored to your specific interests and schedule.$imp318$, $imp319$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · The Ant Adventures service standard: private, personalised, and perfectly ex$imp319$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-25', 'Art retreat (review the previous one)', 'Art retreat (review the previous one).', 'Half Day', 'Arts & Crafts', 'Hue', 'Easy & Comfortable', $imp320$An immersive art retreat experience drawing on Hue's extraordinary tradition of lacquerware, silk painting, and woodblock printing — currently being refined to offer guests the most authentic and creatively stimulating programme available in central Vietnam. The experience pairs guests with working artists in their private studios for sessions of genuine creative collaboration rather than supervised craft activities. Please contact The Ant Adventures to discuss current programme details and sche$imp320$, $imp321$Master artisan access — hands-on participation in a living cultural tradition · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · The Ant Adventures service standard: private, personalised, and perfectly execut$imp321$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-HD-26', 'Yoga retreat', 'Yoga retreat.', 'Half Day', 'Wellness', 'Hue', 'Easy & Comfortable', $imp322$A bespoke yoga and wellness retreat experience set against Hue's most serene natural and architectural backdrops — from early morning practice in the royal gardens to evening meditation beside the Perfume River. This programme is currently being developed in partnership with Hue's finest wellness practitioners and will be available for private bookings on request. Please contact The Ant Adventures for programme details and scheduling options.$imp322$, $imp323$World-class wellness immersion in Vietnam's most serene and pristine setting · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · The Ant Adventures service standard: private, personalised, and perfectly execute$imp323$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-FD-01', 'Hue: Countryside Scooter, Citadel and Tombs (L)', $imp324$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp324$, 'Full Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp325$A full day on the back of a scooter with a knowledgeable private guide reveals the Hue that lies beyond the citadel walls — the rural countryside of rice paddies and pine-forested hills, the royal tombs embedded in the landscape south of the city, and the fishing villages along the lagoon coast where life moves according to tides and seasons rather than tourist schedules. The morning ride heads into the hills to visit two or three of the most atmospheric royal tomb complexes, each chosen for the$imp325$, $imp326$Ground-level exploration by scooter — backstreet addresses no tour bus can navigate · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Countryside Scooter, Citadel and Tombs (L)$imp326$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-FD-02', 'Hoi An: Thien Vien Truc Lam Bach Ma Pagoda – Hue (L)', $imp327$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp327$, 'Full Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp328$The journey from Hoi An north to Hue via the mountain monastery of Truc Lam Bach Ma is one of central Vietnam's finest full-day excursions — a passage through coastal scenery, cloud forest, spiritual atmosphere, and finally the imperial city's own particular grandeur that builds in interest and beauty at every stage. The monastery visit in the cool of the morning — before the cloud that frequently obscures the mountain has fully lifted — offers an atmosphere of meditative stillness enhanced by t$imp328$, $imp329$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hoi An: Thien Vien Truc Lam Bach Ma Pagoda – Hue (L)$imp329$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-FD-03', 'Phong Nha: A Day Exploring Phong Nha "Wet" Cave & Paradise Dry Cave (L)', $imp330$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp330$, 'Full Day', 'Adventure', 'Hue', 'Easy & Comfortable', $imp331$**Phong Nha: A Day Exploring Phong Nha "Wet" Cave ****&**** Paradise Dry Cave (L)** Phong Nha's 'wet' cave — the section of the cave system accessible by boat, where the river runs into the mountain through a series of chambers of extraordinary geological beauty — combined with an afternoon at Paradise Cave, whose five-kilometre interior boulevard of stalactites constitutes one of the finest underground experiences in the world, creates a full day of natural wonder that satisfies even the most g$imp331$, $imp332$Underground world of extraordinary geological scale — one of earth's great natural cathedrals · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Phong Nha: A Day Exploring Phong Nha "Wet" Cave & Paradise Dry C$imp332$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-FD-04', 'Phong Nha: A Day Cycling the Ho Chi Minh Trail & National Park (L)', $imp333$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp333$, 'Full Day', 'Cycling', 'Hue', 'Easy & Comfortable', $imp334$**Phong Nha: A Day Cycling the Ho Chi Minh Trail ****&**** National Park (L)** The Ho Chi Minh Trail, as it passes through the forested mountains of the Phong Nha-Ke Bang National Park, offers a cycling experience of extraordinary historical significance and natural beauty — a day spent pedalling through a landscape that was once among the most bombed and contested in human history, now returned entirely to the forest and its extraordinary biodiversity. A private cycling guide leads a curated se$imp334$, $imp335$Cycling immersion through rice paddies — meditative pace, ground-level discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Phong Nha: A Day Cycling the Ho Chi Minh Trail & National Park (L)$imp335$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-FD-05', 'Hue: Countryside, Citadel and Tombs by Car (L)', $imp336$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp336$, 'Full Day', 'Culinary', 'Hue', 'Easy & Comfortable', $imp337$Hue's most celebrated landmarks, organised into a comprehensive full-day private tour by comfortable car, delivers the imperial city's essential story at the most expansive and unhurried scale available. The morning is devoted to the royal tombs south of the city — at least two selected from the extraordinary collection of Nguyen funerary monuments, each chosen for the narrative it offers and the atmospheric quality of its setting. Lunch at a garden restaurant in the pine forest between the tomb$imp337$, $imp338$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hue: Countryside, Citadel and Tombs by Car (L)$imp338$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HUE-FD-06', 'Hue: A Day Villages and Royal Tombs (L)', $imp339$Hue: A Day Villages and Royal Tombs (L) Phuoc Tich is a peaceful village located 40km north of Hue and best known for po$imp339$, 'Full Day', 'Nature', 'Hue', 'Easy & Comfortable', $imp340$The villages and rural landscapes that surround Hue are as historically significant and visually beautiful as the imperial city itself, and this private full-day excursion discovers them at exactly the right pace. The morning visits the craft villages that have supplied Hue's aesthetic needs for centuries — Phuoc Tich for its traditional pottery, Thanh Toan for its covered bridge and rural temple complex, and the incense-making village of Thuy Xuan where the whole world seems to smell of sandalw$imp340$, $imp341$UNESCO heritage with specialist historian guide — the dynastic story in its full context · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Phuoc Tich is a peaceful village located 40km north of Hue and best k$imp341$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-PHN-DAY-FD-01', 'Phong Nha Cave — Day Exploration (Full Day)', $imp342$Phong Nha Cave | Paradise Cave | World's longest dry cave | UNESCO | Oxalis$imp342$, 'Full Day', 'Nature & Adventure', 'Phong Nha', 'Mid–Premium', $imp343$Phong Nha Cave is the oldest and most spiritually significant of the cave systems within the UNESCO World Heritage park that bears its name — a cathedral of limestone whose inner chambers have been venerated by Vietnamese worshippers since the ninth century and explored by speleologists since the twentieth. A full-day private exploration combines the iconic boat journey into the cave's river-level entrance chambers, where the stalactites hang reflected in the still, dark water, with access to th$imp343$, $imp344$Phong Nha Cave — river boat entry into illuminated chambers, 300 million years of geology · Paradise Cave — world's longest dry cave, formations on a cathedral scale (72m ceiling) · UNESCO World Natural Heritage Site — one of earth's great cave lands$imp344$, 'Mid', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-PHN-ADV-3D2N-01', 'Phong Nha — Hang En Overnight Cave Camp (3 Days 2 Nights)', 'Hang En 3rd largest cave | Oxalis exclusive | Underground camp | Wild swimming', '3 Days 2 Nights', 'Adventure', 'Phong Nha', 'Premium', $imp345$**Day 1 — Into the Forest** The approach to Hang En Cave — the world's third-largest cave and the only major cave in the Son Doong system accessible to trekkers — begins with a day's walk through the primary jungle of the Phong Nha-Ke Bang National Park in the company of expert guides and park rangers who know every species, every trail, and every weather pattern in this extraordinary landscape. The trek covers approximately ten kilometres through forest of increasing wildness and beauty, descen$imp345$, $imp346$Hang En — world's 3rd largest cave, overnight camp beneath a 100m limestone arch · Oxalis Adventure — the ONLY certified operator, internationally recognised safety standards · Underground river swimming in crystal-clear water inside one of earth's g$imp346$, '$300–$500/person', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-01', 'Hoi An: Wander the Ancient Town (L or D)', $imp347$Standard: Route - Hotel - Hoi An Ancient Town (L or D) - Hotel Staying inside Hoi An with walking transfers.  Downgrade $imp347$, 'Half Day', 'Arts & Crafts', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp348$The Ancient Town of Hoi An is one of the few places in Southeast Asia where the physical fabric of a pre-colonial trading city has survived nearly intact — its merchant houses, communal halls, and covered market preserving an architectural world that predates the twentieth century entirely. A private guided wander with a specialist in Hoi An's history moves through the town at the pace of genuine exploration, pausing at the Japanese Covered Bridge whose symbolism rewards extended contemplation, $imp348$, $imp349$UNESCO Ancient Town after dark — lantern light transforming 400 years of heritage · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Your guide will meet you at your hotel at an agreed time and together yo$imp349$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-02', 'Hoi An: Lantern Making', $imp350$Standard: Route - Hotel - Hoi An - Hotel Staying inside Hoi An with walking transfers.  Downgrade options: No meal  Surc$imp350$, 'Half Day', 'Cultural', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp351$The art of lantern-making has been practised in Hoi An for centuries, and the town's coloured silk lanterns — red, yellow, and turquoise swaying in the river breeze — are one of the most immediately recognisable images of central Vietnam. This private workshop, conducted by a family whose lantern-making tradition extends across several generations, teaches the complete process: the bamboo frame shaped by hand into a precise geometric form, the silk stretched and tied with the precision that dist$imp351$, $imp352$UNESCO Ancient Town after dark — lantern light transforming 400 years of heritage · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · You will be met by your guide and taken to a local craftsman in town whe$imp352$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-03', 'Hoi An: Trip to My Son and Tra Que Village (L)', $imp353$Standard: Route: Hotel - My Son - Tra Que (L) - Hotel Staying inside Hoi An with walking transfer.  Downgrade options: N$imp353$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp354$My Son Sanctuary — the ruined Cham temple complex set in a valley of extraordinary scenic beauty an hour from Hoi An — and the organic farming village of Tra Que share a private half-day that moves between archaeological wonder and living agricultural tradition with satisfying coherence. The My Son visit is conducted in the early morning before the heat and the coaches arrive, with a private guide who understands Cham civilisation with the depth that this remarkable culture deserves — its Hindu $imp354$, $imp355$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Trip to My Son and Tra Que Village (L)$imp355$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-04', 'Hoi An: Cam Kim Island Cycle Ride (Half Day) (L or D)', $imp356$Standard: Route: Hotel - Hoi An Hotel - Cam Kim - Countryside - Hoi An Town (L or D) - Hotel Staying inside Hoi An with $imp356$, 'Half Day', 'Cycling', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp357$Cam Kim Island, separated from Hoi An's Ancient Town by a narrow arm of the Thu Bon River, exists in a state of rural tranquillity that makes the crossing feel like a journey between centuries. This private cycle ride traverses the island's network of dike paths and paddy field roads at a pace dictated by the landscape's scale — slow enough to observe the farmers at work, the fishermen returning with the morning's catch, and the craftspeople who have maintained Cam Kim's boat-building and woodca$imp357$, $imp358$Cycling immersion through rice paddies — meditative pace, ground-level discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Cam Kim Island Cycle Ride (Half Day) (L or D)$imp358$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-05', 'Hoi An: Early – Morning Market with Fishing and Craft Villages (S,L)', $imp359$Standard: Route: Duy Hai Market - Duy Hai Fishing Village - Hotel (B) -  Thanh Ha Pottery - Cam Kim Island - Silk Villag$imp359$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp360$Hoi An's morning begins at the market — a sensory immersion in the colours, aromas, and sounds of central Vietnamese commerce that rewards the early start completely. This extended private programme combines a market visit with a journey to one of the fishing villages on the coast road north of town, where the morning's catch is being sorted on the beach as the boats return through the surf, and then a visit to Tra Que herb village before the morning's heat makes outdoor activity less appealing.$imp360$, $imp361$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Early – Morning Market with Fishing and Craft Villages (S,L)$imp361$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-06', 'Hoi An: Early – Morning Market with Fishing (S,L)', 'Tai added', 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp362$The Hoi An fishing tradition is as old as the trading port itself — the boats that brought spices and silk from across the South China Sea were accompanied by the fishing craft that fed the town, and the tradition continues today along beaches and river channels where the methods have changed little in centuries. This private early morning programme visits the beach where the fishing boats return with their catch — a scene of extraordinary activity and colour as nets are sorted, fish are packed $imp362$, $imp363$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Early – Morning Market with Fishing (S,L)$imp363$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-07', 'Hoi An: Sunrise Beach and Markets by Kayak (S)', $imp364$Standard: Road transfers to/from kayaking meeting point. Guests staying inside or outside of Hoi An.  Downgrade options:$imp364$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp365$Hoi An from the water at sunrise is a different city from the one reached by the town's narrow streets — the lanterns still illuminated against the fading night, the market boats beginning their crossing with produce from the mainland farms, and the ancient bridge reflected in the river's pewter surface before the day's warmth turns it to gold. This private kayaking experience launches at first light and explores the waterways surrounding the Ancient Town from the most intimate possible vantage $imp365$, $imp366$Private waterway journey — river scenery, local life, and timeless Vietnamese landscape · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Sunrise Beach and Markets by Kayak (S)$imp366$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-08', 'Hoi An: Kayaking the Coco Palm Forest to Craft Village (S)', $imp367$Standard: Road transfers to/from kayaking meeting point. Guests staying inside or outside of Hoi An.  Downgrade options:$imp367$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp368$The coconut palm forest of Bay Mau — a dense, green waterway system of the Thu Bon delta where the palms grow so thickly that their reflections transform the water surface into a living green ceiling — is explored most memorably aboard the round basket boats that local fishermen have used here for generations. Kayaking into the forest provides an additional dimension of engagement: the paddle dipping into water so clear that the sandy bottom is visible beneath, the sound of the leaves overhead, $imp368$, $imp369$Private waterway journey — river scenery, local life, and timeless Vietnamese landscape · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Kayaking the Coco Palm Forest to Craft Village (S)$imp369$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-09', 'Hoi An: Thanh Ha Craft Village (S)', $imp370$Hoi An: Thanh Ha Craft Village (S) After breakfast, you will move on by private car and spend the rest of the morning le$imp370$, 'Half Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp371$Thanh Ha ceramic village, situated on the Thu Bon River upstream from Hoi An, is the oldest craft settlement in the region — its kilns have been producing the unglazed terracotta for which central Vietnam is famous since the fifteenth century, when Cham potters first taught their techniques to Vietnamese apprentices. A private visit to the village in the morning, before the heat arrives, allows time to move through the working workshops at a reflective pace — watching potters shape vessels on fo$imp371$, $imp372$Master artisan access — hands-on participation in a living cultural tradition · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · After breakfast, you will move on by private car and spend the rest of the m$imp372$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-10', 'Hoi An: Ao Dai – The Long Dress of Vietnam (D)', $imp373$Standard: Staying inside Hoi An with walking transfers.  Downgrade options: text  Surcharged upgrade options on request:$imp373$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp374$The ao dai — Vietnam's national costume, a garment of extraordinary elegance whose origins lie in the eighteenth-century court of Hue — reaches its most refined contemporary expression in the tailoring ateliers of Hoi An, where a tradition of exceptional workmanship has attracted international attention for decades. This private experience begins at one of Hoi An's finest fabric merchants, where a specialist guide assists with the selection of silk, cotton, or brocade from an overwhelming and be$imp374$, $imp375$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Ao Dai – The Long Dress of Vietnam (D)$imp375$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-11', $imp376$Hoi An: Vy's Holiday Private Masterclass with Market (L)$imp376$, $imp377$Standard: Staying inside Hoi An with walking transfers.  Downgrade options: Join group No market visit  Surcharged upgra$imp377$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp378$Vy's Market Restaurant is among the most celebrated cooking schools in Southeast Asia, its programmes designed by one of central Vietnam's most creative and knowledgeable culinary personalities — a chef whose understanding of Hoi An's culinary tradition is matched only by her ability to communicate it with infectious warmth and precision. The private masterclass begins at the morning market, where Vy or a member of her team selects the day's ingredients with the eye of someone who knows every ve$imp378$, $imp379$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Vy's Holiday Private Masterclass with Market (L)$imp379$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-12', 'Hoi An: Walking Foodie (Local food) & Lanterns Release', $imp380$Standard: Staying inside Hoi An with walking transfers.  Downgrade options: None  Surcharged upgrade options on request:$imp380$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp381$**Hoi An: Walking Foodie (Local food) ****&**** Lanterns Release** Hoi An's street food culture is one of the most distinctive and historically layered in Vietnam — a cuisine shaped by centuries of maritime trade that brought influences from Japan, China, India, and Portugal to a small port town that absorbed and transformed them all. This private walking foodie experience, conducted in the cooler hours of late afternoon or evening when the food stalls achieve their full atmospheric effect, visi$imp381$, $imp382$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Walking Foodie (Local food) & Lanterns Release$imp382$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-13', $imp383$Hoi An: Red Bridge Cooking School (Half Day) (D) - Private Group Cooking Class (Afternoon)$imp383$, $imp384$Standard: Staying inside Hoi An with walking transfers to/from Hai Cafe.  Downgrade options: None  Surcharged upgrade op$imp384$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp385$Red Bridge Cooking School has earned its reputation as one of Hoi An's finest culinary institutions through the consistent quality of its teaching and the genuine beauty of its setting — a property on the Thu Bon River where the school's gardens supply the herbs and vegetables used in every class. This private afternoon programme begins with a boat journey downriver from the Ancient Town to the school, a gentle fifteen-minute passage that introduces the landscape and puts the Ancient Town into p$imp385$, $imp386$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Red Bridge Cooking School (Half Day) (D) - Private Group Cook$imp386$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-14', 'Hoi An: Half Day Foodie & Cooking Class at Tra Que (L)', $imp387$Standard: Staying inside Hoi An with road transfers.  Downgrade options: None  Surcharged upgrade options on request: Su$imp387$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp388$**Hoi An: Half Day Foodie ****&**** Cooking Class at Tra Que (L)** The combination of a morning market visit with a cooking class in Tra Que village represents Hoi An's most complete culinary half-day — a programme that connects the source of the ingredients with the techniques that transform them into the dishes for which this region is famous. The market visit with a chef-guide establishes the palate and the pantry for the session that follows, as the morning's selections of herbs, fresh noodl$imp388$, $imp389$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Half Day Foodie & Cooking Class at Tra Que (L)$imp389$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-15', 'Hoi An: Half Day Cooking Class at Tra Que (L)', $imp390$Standard: Staying inside Hoi An with road transfers.  Downgrade options: None  Surcharged upgrade options on request: Su$imp390$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp391$Tra Que village, three kilometres from Hoi An's Ancient Town on the road to the coast, supplies the restaurants of one of Vietnam's most food-obsessed towns with the herbs, vegetables, and aromatics that make central Vietnamese cuisine so distinctive — and a morning cooking class in the village, using produce from its own organic gardens, ensures that every ingredient is as fresh as any restaurant dish can hope to receive. A private chef-instructor leads the session through three or four dishes $imp391$, $imp392$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Half Day Cooking Class at Tra Que (L)$imp392$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-16', 'Hoi An: Tra Que Village Organic Farming (L or D)', $imp393$Standard: Staying inside Hoi An with road transfers.  Downgrade options: Cycle - 3km each way if staying inside Hoi An T$imp393$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp394$Tra Que village operates on a principle of organic agriculture that is both ancient in its methods and progressive in its philosophy — the farmers here have refused the chemical shortcuts that neighbouring villages adopted, maintaining instead the traditional techniques of composting, crop rotation, and natural pest management that make their produce consistently superior. A private morning or afternoon spent as a working participant in the village's daily agricultural activities connects guests$imp394$, $imp395$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Tra Que Village Organic Farming (L or D)$imp395$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-17', 'Hoi An: Walking Cam Kim Island and Boat Ride', 'Tai added', 'Half Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp396$Cam Kim Island's combination of traditional boat-building craft and rural landscape makes it one of the most quietly rewarding destinations in the Hoi An region, and the walk across its network of paths — with a boat crossing that frames the Ancient Town perfectly from the opposite bank — provides both the physical engagement and the visual reward that a half-day in this part of Vietnam deserves. A private guide with knowledge of the island's craft traditions accompanies the walk, pausing at wor$imp396$, $imp397$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Walking Cam Kim Island and Boat Ride$imp397$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-18', 'Danang: Culinary Evening "Di Vong Vong" on Scooter (D)', $imp398$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp398$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp399$Da Nang's culinary culture — distinct from Hoi An's in its emphasis on robust, abundant street food rather than refined court cuisine — is best encountered at scooter pace in the evening, when the night food market opens along the river and the city's residents emerge for the long, social meals that characterise Vietnamese urban life at its most relaxed. This private evening scooter experience, conducted in the spirit of the Vietnamese concept of 'di vong vong' — going around without particular $imp399$, $imp400$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Danang: Culinary Evening "Di Vong Vong" on Scooter (D)$imp400$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-19', 'Danang: Community Support at Danang Street (L)', $imp401$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp401$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp402$Community tourism at its most thoughtfully conceived, this private half-day at Da Nang Street — a social enterprise that trains and employs disadvantaged youth as cooks, servers, and hospitality professionals — provides a lunch experience of considerable quality while supporting a programme of genuine social impact. A private guide provides context on the project's history and methodology before guests are welcomed by the young staff with the warmth and professionalism that the enterprise has wo$imp402$, $imp403$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Danang: Community Support at Danang Street (L)$imp403$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-20', 'Danang: Danang to Hue Private Transfer with Guide (L)', $imp404$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp404$, 'Half Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp405$The private transfer from Da Nang to Hue is most rewarding when it takes the coastal mountain road rather than the faster inland route, ascending through the pine forest to the Hai Van Pass summit where the views of the two coastlines — north to Hue's lagoon, south to Da Nang's perfectly curved bay — create one of the finest panoramas on the entire central Vietnamese coast. A private guide accompanies the journey with commentary on the pass's historical significance — the border it has marked be$imp405$, $imp406$Private transfer with specialist guide — seamless logistics combined with local insight · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Lang Co, Hai Van Pass, Fishing Villages, Cham Museum, Danang Museum, T$imp406$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-21', 'Danang: 4 Hour Foodie Experience by Scooter (S,L)', $imp407$Standard: text  Downgrade options: text  Surcharged upgrade options on request: Pick up and drop off at Intercontinental$imp407$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp408$Da Nang from the back of a scooter, in the hands of a guide who knows the city as a local rather than a tourist destination, reveals a culinary culture of impressive depth and accessibility — the breakfast noodle joints that open at 5am, the bánh mì counters that elevate a French colonial legacy into something entirely Vietnamese, and the seafood restaurants where freshness is measured in hours rather than days. This private four-hour scooter experience treats Da Nang's food scene as the subject$imp408$, $imp409$Ground-level exploration by scooter — backstreet addresses no tour bus can navigate · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Danang: 4 Hour Foodie Experience by Scooter (S,L)$imp409$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-22', 'Hoi An: Afternoon Jeep Wild Life', $imp410$ADDED TO REVIEW Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp410$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp411$The paddy fields and wetland areas surrounding Hoi An support a wildlife community of surprising richness — migratory water birds, resident kingfishers, and the nocturnal fauna of the rice paddy ecosystem that emerges in the cooler late afternoon hours. This private jeep excursion into the landscape west of the town, timed for the golden hour when wildlife activity peaks and the light transforms the landscape's already considerable beauty into something extraordinary, combines naturalist observa$imp411$, $imp412$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Your guide will meet you for your restored army jeep and wildlife experi$imp412$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-23', 'Hoi An: Half Day Cycling & Cooking Class in Tra Que (L)', $imp413$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp413$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp414$**Hoi An: Half Day Cycling ****&**** Cooking Class in Tra Que (L)** The combination of cycling and cooking in Tra Que village creates a half-day of physical pleasure and culinary engagement that is more satisfying than either activity separately — the cycling providing the appetite and the context, the cooking providing the knowledge and the meal. A gentle cycle from Hoi An's Ancient Town along the river road to Tra Que takes approximately twenty minutes through farming landscape of considerable$imp414$, $imp415$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Half Day Cycling & Cooking Class in Tra Que (L)$imp415$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-24', 'Hoi An: Half Day Foodie by Bicycle (L/D)', $imp416$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp416$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp417$The most satisfying way to discover Hoi An's extraordinary food culture is on a bicycle — slow enough to observe, flexible enough to stop anywhere, and gentle enough to sustain for a full morning or evening without discomfort. This private foodie bicycle experience follows a curated route through the Ancient Town's most atmospheric lanes and along the river road to the fishing villages and market streets that supply the town's restaurants with the ingredients that make its cuisine so distinctive$imp417$, $imp418$Curated evening experience — the city at its most atmospheric and alive · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · After setting up your bicycle so you feel comfortable, it is time to set off. As y$imp418$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-25', $imp419$Hoi An: New Year's Eve Celebration in Hoi An & Danang$imp419$, $imp420$Hoi An: New Year's Eve Celebration in Hoi An & Danang (~ 19:00 - 01:00) Enjoy the delicious and special regional Vietnam$imp420$, 'Half Day', 'Experience', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp421$**Hoi An: New Year's Eve Celebration in Hoi An ****&**** Danang** New Year's Eve in Hoi An and Da Nang is one of the most spectacular celebrations in all of Southeast Asia — the Ancient Town illuminated entirely by traditional lanterns, the Han River in Da Nang ablaze with the fireworks that rival any display in the region, and the streets of both cities filled with the spontaneous joy of a community that celebrates the new year with complete abandon and total generosity toward its visitors. Thi$imp421$, $imp422$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: New Year's Eve Celebration in Hoi An & Danang$imp422$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-26', 'Hoi An: Tra Nhieu Village Cycle Ride', $imp423$Hoi An: Tra Nhieu Village Cycle Ride (~ 08:00 - 14:00) Meet up with your guide at a pre-agreed location to prepare for y$imp423$, 'Half Day', 'Cycling', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp424$Tra Nhieu village, on the northern shore of the Thu Bon River across from Hoi An's Ancient Town, exists in a state of rural authenticity that the Ancient Town itself — however beautiful — can no longer claim. This private cycle ride crosses the river by small boat and explores the village's dike roads through paddy fields and fishing settlements, passing the communal house that serves as the social centre of a community whose life revolves around the agricultural and fishing calendars with an or$imp424$, $imp425$Cycling immersion through rice paddies — meditative pace, ground-level discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Meet up with your guide at a pre-agreed location to prepare for your cycl$imp425$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-27', $imp426$Hoi An: Discovering The Cham Traditional Silk Journey from Mulberry Tree to Fabric$imp426$, $imp427$Hoi An: Discovering The Cham Traditional Silk Journey from Mulberry Tree to Fabric (~ 08:00 - 12:00) Hoi An has become w$imp427$, 'Half Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp428$The Cham people ruled the central coast of Vietnam for over a thousand years, leaving behind at My Son one of Southeast Asia's most remarkable collections of Hindu temple architecture — and leaving behind, less obviously, a living silk-weaving tradition that persists in the hands of Cham artisans whose techniques have been passed across fifty generations without interruption. This private experience traces that living thread: a visit to a Cham weaving workshop where the traditional techniques of$imp428$, $imp429$Master artisan access — hands-on participation in a living cultural tradition · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Discovering The Cham Traditional Silk Journey from Mulberry Tree to $imp429$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-28', 'Hoi An: Eco-Kayaking Cleanup Challenge', $imp430$Hoi An: Eco-Kayaking Cleanup Challenge (~ 13:30 - 16:00) Your adventure begins at Cam Thanh Village! Your guide will tak$imp430$, 'Half Day', 'Adventure', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp431$Hoi An's UNESCO status was earned in part through the extraordinary preservation of its historic fabric, but the water that defines its physical character — the Thu Bon River and its tributaries — is under growing pressure from agricultural runoff, plastic waste, and development. This private kayaking experience combines the pleasure of exploring Hoi An's waterways with active participation in an ongoing environmental cleanup operation led by local conservationists, paddling the river reaches wh$imp431$, $imp432$Private waterway journey — river scenery, local life, and timeless Vietnamese landscape · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Your adventure begins at Cam Thanh Village! Your guide will take y$imp432$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-29', 'Hoi An: My Son by Sunrise', $imp433$Hoi An: My Son by Sunrise (~ 05:00 - 09:30)  My Son Sanctuary is fascinating archaeological site with ruinous temples.$imp433$, 'Half Day', 'Cultural', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp434$My Son Sanctuary at dawn — before the morning heat, before the tourist coaches, before anything but the mist and the birds and the remarkable fact of these Hindu towers surviving in the forest for seventeen centuries — is an experience of such atmospheric richness that guests who make the early start consistently cite it as one of their most treasured travel moments. A private vehicle departs Hoi An well before sunrise, arriving at the sanctuary as the first light touches the tallest towers with$imp434$, $imp435$Dawn departure — the destination before the crowds, in its most magical light · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · My Son Sanctuary is fascinating archaeological site with ruinous temples. Ou$imp435$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-30', 'Hoi An: Historical and Cultural Tam Ky', $imp436$Hoi An: Historical and Cultural Tam Ky (~ 07:00 - 15:00, 50 minute road transfer each way) Giving back to the community $imp436$, 'Half Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp437$Tam Ky — the provincial capital of Quang Nam, an hour south of Hoi An — preserves a historical and cultural character that its more famous neighbour's tourism success has inevitably overshadowed, and this private half-day excursion discovers it with the attention it deserves. The My Son Group G and H temple clusters in the surrounding countryside are less visited and in many ways more atmospherically intact than the main My Son complex, offering close encounters with Cham architecture without th$imp437$, $imp438$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · (~ 07:00 - 15:00, 50 minute road transfer each way)$imp438$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-31', 'Hoi An: One Day Hue Excursion **Lunch at Ben Xuan Garden House Theater', $imp439$Hoi An: One Day Hue Excursion **Lunch at Ben Xuan Garden House Theater (~ 07:30 - 20:00) Your guide will accompany you o$imp439$, 'Half Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp440$**Hoi An: One Day Hue Excursion **Lunch at Ben Xuan Garden House Theater** The full-day excursion from Hoi An to Hue and back, incorporating lunch at the legendary Ben Xuan Garden House, offers a compressed version of the imperial city experience in a format that suits guests who cannot extend their central Vietnam stay but refuse to miss Hue entirely. A private vehicle and guide depart Hoi An in the early morning, reaching Hue by mid-morning for visits to the most essential imperial sites — the$imp440$, $imp441$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Imperial capital — Hue's royal architecture, cuisine, and soul in one experience · Hoi An: One Day Hue Excursion **Lunch at Ben Xuan Garden House Theater$imp441$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-32', 'Bach Ma to Hoi An by Scooter', $imp442$Bach Ma to Hoi An by Scooter From your hotel, we will bring you by road transport through the Hai Van Tunnels and into t$imp442$, 'Half Day', 'Arts & Crafts', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp443$The scooter journey from Bach Ma National Park to Hoi An follows one of the most scenically varied routes on the central coast — descending from the cool cloud forest of the national park through the farming villages of the coastal plain, crossing the lagoon at Lang Co, and finally arriving at the Ancient Town as the afternoon light makes its lanterns and river reflections most beautiful. A private scooter guide leads the route at a pace that honours the landscape's variety — pausing for the vie$imp443$, $imp444$Ground-level exploration by scooter — backstreet addresses no tour bus can navigate · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · From your hotel, we will bring you by road transport through the Hai V$imp444$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-HD-33', 'Hoi An: Ba Na Hills', $imp445$Hoi An: Ba Na Hills (~ 10:00 - 16:00) A road transfer and a cable car ride brings you to the iconic Golden "Hand" Bridge$imp445$, 'Half Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp446$Ba Na Hills, the French colonial hill station above Da Nang, commands a mountaintop position that places it above the clouds for much of the year — a landscape of surreal beauty when the mist curls around the mock-European castle and the surrounding forest drips with condensation. The cable car journey to the summit is extraordinary in itself — a 5.7-kilometre ascent that holds multiple world records and delivers views of the Da Nang coastline that are simply not available from any other vantage$imp446$, $imp447$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · A road transfer and a cable car ride brings you to the iconic Golden "Ha$imp447$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-FD-01', 'Danang: Full Day Danang Pass (L)', $imp448$Standard: text  Downgrade options: text  Surcharged upgrade options on request: International cruise pier pick up/drop o$imp448$, 'Full Day', 'Adventure', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp449$Da Nang Pass — the Hai Van, the 'Pass of Ocean Clouds' — is one of the most famous mountain roads in Southeast Asia, and a full day dedicated to exploring its northern and southern approaches along with the coastal scenery it commands provides a journey of sustained scenic richness. A private vehicle and guide make the most of the morning light on the northern coast, visiting the former imperial beach resort of Lang Co before ascending to the pass summit, where the wartime fortifications and pan$imp449$, $imp450$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · At Marble Mountain take the 1.5hr hike up the mountain steps and your gu$imp450$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-FD-02', 'Danang: 8 Hour Culture & Culinary Experience by Scooter (S,L)', $imp451$Standard: text  Downgrade options: text  Surcharged upgrade options on request: Pick up and drop off at Intercontinental$imp451$, 'Full Day', 'Culinary', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp452$**Danang: 8 Hour Culture ****&**** Culinary Experience by Scooter (S,L)** Eight hours of Da Nang's culinary and cultural life, explored by scooter with a private guide of exceptional local knowledge, delivers the city in its full, exuberant complexity — from the dawn fish market where the night's catch is auctioned on the beach to the evening beer garden where the city's residents gather to celebrate the end of another magnificent day. The morning's scooter circuit visits the food markets, the H$imp452$, $imp453$Hands-on culinary immersion with a specialist local guide — markets, method, mastery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Danang: 8 Hour Culture & Culinary Experience by Scooter (S,L)$imp453$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-FD-03', 'Hoi An: Truc Lam Bach Ma Pagoda – Lang Co (L)', $imp454$ADDED TO REVIEW Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp454$, 'Full Day', 'Nature', 'Hoi An & Da Nang', 'Easy & Comfortable', $imp455$The mountain monastery of Truc Lam Bach Ma, set at 1,200 metres in the cloud forest of Bach Ma National Park between Hue and Hoi An, combines the spiritual atmosphere of a functioning Buddhist retreat with natural surroundings of extraordinary beauty — the forest alive with birds and insects, the valley below visible on clear days in a sweep of coastal plain that ends at the South China Sea. A private full-day excursion from Hoi An makes the ascent by a combination of private vehicle and the mon$imp455$, $imp456$Private specialist guide — exclusive access, authentic depth, unhurried discovery · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Hoi An: Truc Lam Bach Ma Pagoda – Lang Co (L)$imp456$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-HOI-FD-04', 'Hoi An: Bach Ma National Forest Trek (L)', $imp457$ADDED TO REVIEW Standard: text  Downgrade options: text  Surcharged upgrade options on request: text$imp457$, 'Full Day', 'Adventure', 'Hoi An & Da Nang', 'Moderate', $imp458$Bach Ma National Park — the former French colonial hill station transformed into a protected forest of exceptional biodiversity — is one of central Vietnam's finest natural assets, and a full day's trekking within its ancient forest provides an experience of wildlife richness and physical satisfaction that few other itineraries in the region can match. A private naturalist guide leads the chosen trail through primary forest where the canopy closes overhead and the humidity of the lowland gives w$imp458$, $imp459$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · UNESCO Ancient Town — Asia's most intact historic port, culinary capital of Central Vietnam · Your guide and driver will meet you in your hotel reception at 07$imp459$, '', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-QNH-BCH-3D2N-01', $imp460$Quy Nhon — Vietnam's Undiscovered Coast (3 Days 2 Nights)$imp460$, 'Ky Co Island | Cham towers | Authentic fishing | Avani resort | Zero crowds', '3 Days 2 Nights', 'Beach & Culture', 'Quy Nhon / Binh Dinh', 'Mid–Premium', $imp461$**Day 1 — Arrival on the Undiscovered Coast** Quy Nhon occupies a position of considerable natural beauty — a crescent bay of fine sand sheltered by forested headlands, with a town that has maintained its fishing-village character despite the gradual arrival of more discerning travellers. The journey from Da Nang or Hoi An by private vehicle follows the coastal road through scenery of increasing beauty, passing the Cham tower ruins at Duong Long — the tallest surviving Cham towers in all of Viet$imp461$, $imp462$Ky Co Island — pristine turquoise water and almost zero international visitors · Best-preserved Cham towers outside My Son (Banh It, Duong Long) — history without crowds · Authentic fishing village culture — not performing for tourists, genuinely liv$imp462$, 'Mid–Premium', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-KON-COM-2D1N-01', 'Kon Tum — Bahnar Longhouse & Ethnic Highland (2 Days 1 Night)', 'Bahnar rong house | Gong music | Rice wine ceremony | Suspension bridge | UNESCO', '2 Days 1 Night', 'Community & Culture', 'Kon Tum / Central Highlands', 'Mid', $imp463$**Kon Tum — Bahnar Longhouse ****&**** Ethnic Highland (2 Days 1 Night)** **Day 1 — The Central Highlands Revealed** Kon Tum is the gateway to Vietnam's central highlands — a landscape of forest, river, and ethnic minority culture that remains among the country's least touristed and most genuinely rewarding destinations for travellers who seek authentic cultural encounter over polished heritage. The journey from Hoi An or Da Nang by private vehicle ascends into the highlands through scenery of i$imp463$, $imp464$Bahnar and Jarai rong longhouses — distinctive architecture found nowhere else in Vietnam · UNESCO gong music tradition — ceremony and genuine community participation · Rice wine welcome ceremony — immersive and genuinely hospitable$imp464$, '$100–$150/person', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-CV-DAN-LUX-4D3N-01', 'Da Nang Coastal Luxury Circuit (4 Days 3 Nights)', $imp465$Intercontinental Da Nang | Montgomerie Links golf | Spa | Marble Mountains | Lady Buddha$imp465$, '4 Days 3 Nights', 'Luxury & Leisure', 'Da Nang', 'Ultra Luxury', $imp466$**Day 1 — Da Nang: Coast and Contemporary** The Da Nang Coastal Luxury Circuit begins in Vietnam's most dramatically situated city — a place of extraordinary natural beauty where the marble mountains meet a bay of such perfect curvature that architects of the contemporary hotel boom have simply arranged their buildings to face it. The first day establishes the circuit's defining character: private vehicle, specialist guide, and an itinerary that moves between Da Nang's finest contemporary dining$imp466$, $imp467$Intercontinental Da Nang — consistently ranked among Asia's top 10 resorts · Bill Bensley-designed — Vietnam's most architecturally spectacular resort property · Montgomerie Links & BRG Da Nang — premier golf in one of Asia's finest settings$imp467$, '$500–$1,500/person/night', 'central') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-SGN-CULI-EVE-01', 'Saigon After Dark — Street Food by Motorbike', 'XO Tours | Women riders | Ao dai | Street food | Vespa | Hidden streets', 'Evening (3–4 hours)', 'Culinary & Night Life', 'Ho Chi Minh City', 'Mid', $imp468$After dark, Saigon reveals its most intoxicating character — a city of ten million people that collapses the formal boundaries between street and restaurant, public and private, past and present into a single exhilarating evening spectacle best experienced at motorbike speed. This private food discovery tour by motorbike moves through the city's most atmospheric districts in the hour after sunset, when the pavement restaurants extend their plastic tables into the street, the bánh mì carts fire u$imp468$, $imp469$XO Tours — women riders in ao dai: the most stylish motorbike food experience in Southeast Asia · Vietnam Vespa Adventure — vintage scooters through hidden city streets inaccessible by car · Backstreet food addresses impossible for a tourist to find $imp469$, '$35–$55/person', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-SGN-BOA-EVE-01', 'Saigon River Dinner Cruise', 'Saigon skyline | River cruise | Live music | Dinner on board | City lights', 'Evening (2–3 hours)', 'Scenic & Romantic', 'Ho Chi Minh City', 'Mid–Premium', $imp470$The Saigon River at night is a different waterway from the one observed by day — its surface illuminated by the reflections of the rapidly evolving skyline, its banks alive with the sounds of riverside restaurants and the lights of cargo vessels moving between the city's port and the South China Sea. A private dinner cruise aboard a traditionally styled river vessel provides the most gracious possible perspective on this extraordinary urban waterscape, combining a multi-course dinner of the fine$imp470$, $imp471$Saigon skyline by night — Landmark 81, Bitexco Tower, colonial riverfront all illuminated · Live music on board — traditional Vietnamese ensemble or jazz, city reflections on the river · Perfect arrival evening for first-timers — the city revealed fr$imp471$, 'Mid–Premium', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-SGN-CT-FD-01', 'Saigon City Discovery (Full Day)', 'War Remnants Museum | Reunification Palace | Ben Thanh | Notre-Dame | History', 'Full Day', 'Cultural & History', 'Ho Chi Minh City', 'Mid', $imp472$Saigon — officially Ho Chi Minh City but universally known by its prerevolutionary name among the people who love it most — is one of Southeast Asia's most dynamic, historically complex, and endlessly stimulating urban experiences, and a private full-day exploration with a knowledgeable guide does genuine justice to its extraordinary depth. The morning visits the sites that form the essential framework: the Reunification Palace (frozen in 1975 like a fly in amber, its interiors unchanged since t$imp472$, $imp473$War Remnants Museum — one of SE Asia's most powerful and essential historical museums · Reunification Palace — the room where the Vietnam War ended, preserved as it was on 30 April 1975 · French colonial architecture: Notre-Dame Cathedral and Eiffel'$imp473$, 'Mid', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-CCH-FD-01', 'Cu Chi Tunnels — Ben Duoc Premium Experience (Full Day)', 'Ben Duoc | 200km tunnels | Wartime history | Jungle | Authentic | Low crowds', 'Full Day', 'Historical & Adventure', 'Cu Chi', 'Mid', $imp474$The Cu Chi tunnel system — 250 kilometres of underground passageways dug by hand through red laterite clay in the years between 1948 and 1968 — represents one of the most extraordinary feats of human determination and ingenuity in military history, and the Ben Duoc site offers a more intimate, less commercialised experience than the more famous Ben Dinh complex. A private full-day excursion from Saigon, conducted with a specialist guide whose knowledge of the tunnel system's engineering, tactica$imp474$, $imp475$Ben Duoc — far more authentic and historically complete than tourist-heavy Ben Dinh · 200km tunnel network: sleeping quarters, hospitals, kitchens — an underground city · Specialist military history guide: context that transforms sightseeing into und$imp475$, 'Mid', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-01', 'Mekong: Cycling in Can Tho with Trek/Trail Bicycles (L)', $imp476$ONLY SHOPPER (MARTIN) NOW AVAILABLE - Check again Usually upgraded on Mekong: Can Tho Markets and Waterways (S) Route: C$imp476$, 'Half Day', 'Cycling', 'Mekong Delta', 'Easy & Comfortable', $imp477$Can Tho is the Mekong Delta's most sophisticated city — a river town of considerable charm whose tree-lined boulevards and French colonial architecture suggest a prosperity built, correctly, on the extraordinary agricultural fertility of the surrounding delta. A private cycling excursion through Can Tho's riverside neighbourhoods and market streets, using high-quality Trek or Trail bicycles maintained to a standard rarely found in Vietnam's cycling hire market, reveals the city at exactly the ri$imp477$, $imp478$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Cycling in Can Tho with Trek/Trail Bicycles (L)$imp478$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-02', 'Mekong: Cai Be Trek/Trail Bicycle Upgrade', 'maintenance?? From Saigon', 'Half Day', 'Cycling', 'Mekong Delta', 'Easy & Comfortable', $imp479$The cycling upgrade to Trek or Trail bicycles for the Cai Be excursion transforms a standard delta exploration into a physical experience of considerably greater quality — the better bikes handling the delta's variable terrain with a confidence and comfort that make a longer, more ambitious route perfectly feasible. The Cai Be circuit follows the orchard-lined roads of Tien Giang Province through landscape that produces the finest tropical fruit in the delta: durian of extraordinary fragrance, d$imp479$, $imp480$Expert-guided trekking through landscapes of extraordinary cultural and natural richness · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Cai Be Trek/Trail Bicycle Upgrade$imp480$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-03', 'Mekong: Can Tho Evening Foodie & Orientation (D)', $imp481$Foodie and walking in Can Tho with guide  This is an extension for guests staying in Can Tho (Azerai Can Tho, Victoria C$imp481$, 'Half Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp482$**Mekong: Can Tho Evening Foodie ****&**** Orientation (D)** Can Tho's evening food culture is the most reliable indicator of what the Mekong Delta's culinary tradition looks like when it is allowed to express itself without concession to outside taste — rich, abundant, fresh, and consumed with the unhurried pleasure of people who know exactly how good their food is. This private evening foodie excursion begins with a river orientation aboard a small private boat — the perspective from the water$imp482$, $imp483$Curated evening experience — the city at its most atmospheric and alive · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Can Tho Evening Foodie & Orientation (D)$imp483$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-04', 'Mekong: Ap Bac Stop Extension', $imp484$Ap Bac: https://en.wikipedia.org/wiki/Battle_of_Ap_Bac  Note for if included on day 1 of Mekong: Classic Can Tho 2D1N as$imp484$, 'Half Day', 'Experience', 'Mekong Delta', 'Easy & Comfortable', $imp485$Ap Bac is a name that resonates through American military history as the site of one of the war's earliest and most consequential engagements — a 1963 battle in which a Viet Cong unit of 350 fighters held off a South Vietnamese force of 1,500 supported by American helicopters and advisors, demonstrating for the first time the tactical sophistication and strategic determination of the resistance. This private stop extension incorporates the Ap Bac battlefield and memorial into a broader delta iti$imp485$, $imp486$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · On the way stop by Ap Bac and learn of the battle that happened there$imp486$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-05', 'Mekong: Xeo Quyt Stop Extension', $imp487$https://vietnamnews.vn/travel/900994/lost-in-xeo-quyt-national-historic-site-in-dong-thap.html  Note for if included on $imp487$, 'Half Day', 'Experience', 'Mekong Delta', 'Easy & Comfortable', $imp488$Xeo Quyt Forest, in Dong Thap Province, is one of the Mekong Delta's finest natural remnants — a section of melaleuca (cajuput) forest that sheltered Viet Minh and later Viet Cong fighters for decades, its channels and walkways now accessible by rowboat and raised wooden walkway to visitors who come for the remarkable ecosystem rather than the wartime history. A private boat excursion through the narrow waterways of the forest, accompanied by a guide whose knowledge of both the ecology and the h$imp488$, $imp489$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Stop at Xeo Quyt to explore this Viet Cong Base. Within the mangrove $imp489$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-06', 'Mekong: Livelihoods and Communities of the Mekong Delta', $imp490$**Depending on the season, tides and timing we may be able to also explore the local canal waterways early in the mornin$imp490$, 'Half Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp491$The communities of the Mekong Delta have developed, over centuries, an extraordinarily intimate relationship with the water systems that both sustain and threaten them — a relationship expressed in the floating markets, the stilt-house villages, the network of canals that serves as both road and larder for millions of people. This private excursion investigates that relationship with the curiosity and respect it deserves, visiting both a traditional fishing village where nets are made and mainta$imp491$, $imp492$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Livelihoods and Communities of the Mekong Delta$imp492$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-07', 'Mekong: Phu An Extension (S)', $imp493$Ba Ton Bridge start.  Standard: Cycling  Downgrade options: Walking  Surcharged upgrade options on request: Trek/trail b$imp493$, 'Half Day', 'Cycling', 'Mekong Delta', 'Easy & Comfortable', $imp494$Phu An Bamboo Village, near Chau Doc, is both an extraordinary natural site and a community enterprise of considerable sophistication — a bamboo forest of such density and height that walking through it feels like entering a different climate zone, and a centre where local craftspeople work the bamboo into furniture, instruments, and utensils that are sold throughout the region. This private extension stop combines a boat journey through the bamboo channels, where the stems arch overhead to crea$imp494$, $imp495$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Near Phu An board a small private boat for a river cruise along the s$imp495$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-08', 'Phnom Penh - Chau Doc by Speedboat (B)', $imp496$Add a speedboat service line item If this is not the Victoria speedboat then the guests will need a short road transfer $imp496$, 'Half Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp497$The speedboat journey from Phnom Penh to Chau Doc along the Mekong River crosses one of Southeast Asia's most historically significant waterways — the river that has connected Cambodia and Vietnam for millennia of trade, warfare, and cultural exchange — in a vessel fast enough to make the journey comfortable and open enough to appreciate the scenery as it unfolds on both banks. A private guide accompanies the journey with commentary on the river's geography, its ecology, and the communities visi$imp497$, $imp498$Private waterway journey — river scenery, local life, and timeless Vietnamese landscape · The great river delta — waterways, floating markets, lotus fields, and timeless community life · The Ant Adventures service standard: private, personalised, and$imp498$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-09', 'Chau Doc: Transfer from Pier to Hotel', $imp499$Chau Doc: Transfer from Pier to Hotel Your guide will meet you as you disembark and will transfer you to your hotel.$imp499$, 'Half Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp500$The transfer from Chau Doc's river pier to the town's hotels and guesthouses is an opportunity to observe a river community in its most active and atmospheric daily state — the floating market vendors setting up for the morning's trade, the fishing boats returning from overnight excursions on the river, and the Cham and Vietnamese families beginning their river-oriented days in the spaces between water and land that define life in this extraordinary border town. A private vehicle and guide ensur$imp500$, $imp501$Private transfer with specialist guide — seamless logistics combined with local insight · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Your guide will meet you as you disembark and will transfer you$imp501$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-10', 'Can Tho: The Heart of the Delta', $imp502$Standard: text  Downgrade options: text  Surcharged upgrade options on request: text  ICT will provide directly (not thr$imp502$, 'Half Day', 'Cultural', 'Mekong Delta', 'Easy & Comfortable', $imp503$Can Tho, the delta's de facto capital and most cosmopolitan city, rewards the traveller who approaches it with genuine curiosity rather than merely as a base for floating market excursions — and this private private half-day reveals its full character with the depth it deserves. The morning begins at the Binh Thuy Ancient House, a Vietnamese-French colonial hybrid of extraordinary elegance whose family has maintained both the building and the story it tells with remarkable fidelity, before movin$imp503$, $imp504$Master artisan access — hands-on participation in a living cultural tradition · The great river delta — waterways, floating markets, lotus fields, and timeless community life · The Mekong Delta boasts a rich melting pot of cultures and architecture f$imp504$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HD-11', 'Azerai Can Tho: The Lost Kingdom Exploration (Private)', $imp505$Standard: Time: 08:00 AM, half day Duration: Approximately 3-4 hours.  ICT will arrange through the Azerai Can Tho: http$imp505$, 'Half Day', 'Cultural', 'Mekong Delta', 'Easy & Comfortable', $imp506$Azerai Can Tho is among Vietnam's finest luxury properties — a resort of exceptional architectural refinement set on a private island in the Hau River, its villas and pavilions arranged around water gardens and tropical plantings that create an atmosphere of complete serenity. The 'Lost Kingdom' experience available exclusively to guests of The Ant Adventures pairs access to the resort's most atmospheric spaces with a private exploration of the island's own natural and cultural landscape — the w$imp506$, $imp507$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Azerai Can Tho: The Lost Kingdom Exploration (Private)$imp507$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-ANG-ECO-HD-01', 'Tra Su Cajuput Forest — Hidden Gem (Half Day)', $imp508$Flooded forest | Row boat | Lotus fields | Bird watching | Zero tourists | An Giang$imp508$, 'Half Day', 'Nature & Eco', 'An Giang / Mekong Delta', 'Mid', $imp509$Tra Su Cajuput Forest in An Giang Province is one of the Mekong Delta's most spectacular and least-visited natural environments — a vast wetland forest of silver-barked melaleuca trees whose flooded channels turn the morning light into something extraordinary when reflected in the tea-brown water between the trunks. A private boat excursion through the forest's interior waterways, accompanied by a local naturalist guide, reveals a world of remarkable ecological richness: colonies of nesting hero$imp509$, $imp510$Zero international tourists — a genuine Vietnamese secret known only to local travellers · Flooded cajuput forest by row boat — one of Vietnam's most serene and beautiful half-days · October–November lotus bloom: acres of pink flowers across mirror-s$imp510$, 'Budget–Mid', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-FD-01', 'Mekong: Cai Be Explorer (L)', $imp511$Please advise if you need us to upgrade to trek/trail bicycles. These would need bringing from Saigon and so would be a $imp511$, 'Full Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp512$Cai Be floating market — though diminished from its peak by the expansion of road transport — remains one of the Mekong Delta's most atmospheric and visually extraordinary experiences, best appreciated from a private wooden boat that moves through the trading vessels at eye level, close enough to smell the durian and hear the negotiations. A full-day Cai Be exploration, conducted by private boat and guided by someone who understands both the history and the present reality of the delta's water-b$imp512$, $imp513$Largest floating market in the Mekong — wholesale trade at its most dramatic before 7am · The great river delta — waterways, floating markets, lotus fields, and timeless community life · (~7:30 - 17:30, 2.5hrs road transfer/way)$imp513$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-FD-02', 'Mekong: Livelihoods and Communities of Cai Be (L)', 'Tai added', 'Full Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp514$The livelihoods and communities of Cai Be reveal themselves most completely to the traveller who moves through the district at the unhurried pace of a private boat, spending long enough at each stop to observe not just the activity but the social fabric that surrounds it. This full-day private exploration visits the floating market in its morning bustle, the orchard villages where farmers harvest dragon fruit and longan with the ease of long practice, and the canal-side communities where an enti$imp514$, $imp515$Largest floating market in the Mekong — wholesale trade at its most dramatic before 7am · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Livelihoods and Communities of Cai Be (L)$imp515$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-FD-03', 'Mekong: Saigon - Cai Be - Vinh Long - Can Tho (L)', $imp516$This is a day 1 option for heading from Saigon down into the Mekong River Delta to stay in Can Tho (Azerai Can Tho, Vict$imp516$, 'Full Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp517$The classic full-day journey from Saigon through Cai Be, Vinh Long, and Can Tho provides the complete Mekong Delta experience in its most comprehensive form — a day that moves from the market theatrics of the upper delta through the orchard islands of the middle delta to the urban sophistication of Can Tho, covering the full geographic and cultural range of a region that consistently astonishes visitors with its scale, its fertility, and its extraordinary hospitality. A private vehicle for the S$imp517$, $imp518$Largest floating market in the Mekong — wholesale trade at its most dramatic before 7am · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Saigon - Cai Be - Vinh Long - Can Tho (L)$imp518$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-FD-04', 'Mekong: Can Tho - Vinh Long - Cai Be - Saigon (L)', $imp519$No cycling Water hyacinth = organic and needs checking if re-opened Banana leaf hammocks Puffed rice Sau Ca fruit orchar$imp519$, 'Full Day', 'Culinary', 'Mekong Delta', 'Easy & Comfortable', $imp520$The reverse direction — from Can Tho through Vinh Long and Cai Be back to Saigon — offers the Mekong Delta experience in a narrative arc that moves from the river's most settled and urbanised expression toward its upper delta origins, ending in the city whose commercial energy gave the entire region its agricultural direction. The morning begins with Can Tho's famous floating market at its earliest and most active hour, before a boat journey through the Vinh Long province's extraordinary network$imp520$, $imp521$Largest floating market in the Mekong — wholesale trade at its most dramatic before 7am · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: Can Tho - Vinh Long - Cai Be - Saigon (L)$imp521$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-FD-05', 'Mekong: A Day to Explore Tan Loc Island (L)', $imp522$This is an extension for guests staying in Can Tho (Azerai Can Tho, Victoria Can Tho, homestay…).$imp522$, 'Full Day', 'Nature', 'Mekong Delta', 'Easy & Comfortable', $imp523$Tan Loc Island, in the Can Tho section of the Mekong River, combines the delta's most characteristic natural beauty with a community life of remarkable authenticity — the island's orchard economy and fishing traditions persisting almost entirely unchanged by the tourism that has transformed the mainland opposite. A full day on the island, arriving by private boat and departing the same way, provides the rare experience of a delta community encountered without the distortions that road access ine$imp523$, $imp524$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Mekong: A Day to Explore Tan Loc Island (L)$imp524$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-FD-06', 'Chau Doc - Can Tho (L)', $imp525$Chau Doc - Can Tho (L) Your guide will meet you at your hotel and take you by small boat to visit the Cham Village nearb$imp525$, 'Full Day', 'Nature', 'Mekong Delta', 'Easy & Comfortable', $imp526$The journey from Chau Doc to Can Tho by private boat traces the Hau River through a landscape of increasing agricultural intensity and human ingenuity — the fish farms of the upper river giving way to the rice paddies and fruit orchards of the lower delta as the boat moves south through one of the most productive agricultural systems on earth. A private guide accompanies the journey with commentary on the river's ecology, the farming communities visible from the water, and the history of the del$imp526$, $imp527$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · Your guide will meet you at your hotel and take you by small boat to $imp527$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-CTH-FLT-FD-01', 'Cai Rang Floating Market — Can Tho (Full Day)', $imp528$Largest floating market | Victoria Can Tho | Private boat | Dawn departure | Delta life$imp528$, 'Full Day', 'Culture & Authentic', 'Can Tho / Mekong Delta', 'Mid–Premium', $imp529$Cai Rang floating market is the largest and most spectacular of the Mekong Delta's waterborne markets — a daily gathering of hundreds of boats trading the agricultural produce of the surrounding provinces in a tradition that predates roads, bridges, and motorised transport entirely. An early private boat departure from Can Tho arrives at the market as the trading reaches its peak intensity, the wholesale fruit and vegetable vendors advertising their cargo by hanging sample produce from bamboo po$imp529$, $imp530$Largest floating market in the Mekong — wholesale trade at its most dramatic before 7am · Victoria Can Tho private boat — dawn departure, breakfast on board, intimate canal return · Stem-flag identification system — each boat's produce indicated by a$imp530$, 'Mid–Premium', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-2D-01', 'Mekong: Classic Can Tho 2D1N', $imp531$Combo: Day 1: Mekong: Saigon - Cai Be - Vinh Long - Can Tho (L) Day 2: Mekong: Can Tho Markets and Waterways (S)$imp531$, '2 Days 1 Night', 'Experience', 'Mekong Delta', 'Easy & Comfortable', $imp532$**Day 1 — Can Tho: The River Capital** Can Tho is the Mekong Delta's largest city and its most sophisticated expression of what happens when a river community has centuries to develop its relationship with the water that sustains it — the result being a city of considerable elegance whose riverside boulevards, French colonial buildings, and extraordinary floating market create an urban environment unlike any other in Vietnam. Arrival by private vehicle from Saigon or the airport is followed by a$imp532$, $imp533$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · The Ant Adventures service standard: private, personalised, and perfe$imp533$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-2D-02', 'Mekong: Gecko Eyes', $imp534$Private 2-day Exclusive Cruise to the Flower Villages around Sa Dec DAY 1   11.30    Boarding of the cruise vessel in Ca$imp534$, '2 Days 1 Night', 'Experience', 'Mekong Delta', 'Easy & Comfortable', $imp535$**Day 1 — Gecko Eyes: Into the Waterways** 'Gecko Eyes' — The Ant Adventures' own named version of the most intimate Mekong Delta exploration available — begins at a point in Can Tho Province where the main rivers give way to the canal network that true delta travellers know is where the region's real character lives. A narrow private boat enters waterways too small for tourist cruises but perfectly sized for observation: the boat moves at walking pace through a green tunnel of overhanging palms$imp535$, $imp536$Private specialist guide — exclusive access, authentic depth, unhurried discovery · The great river delta — waterways, floating markets, lotus fields, and timeless community life · The Ant Adventures service standard: private, personalised, and perfe$imp536$, '', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-HMS-2D1N-01', 'Mekong Delta Homestay & Cycling (2 Days 1 Night)', 'Stilted family home | Dawn fishing | Cycling rice paddies | Cooking | An Giang', '2 Days 1 Night', 'Community & Slow Travel', 'An Giang / Mekong Delta', 'Mid', $imp537$**Mekong Delta Homestay ****&**** Cycling (2 Days 1 Night)** **Day 1 — Delta Depths by Bicycle and Boat** The Mekong Delta homestay experience begins with movement — a bicycle ride through the canal-side villages of Vinh Long Province where the roads follow the waterways with geometric precision and the landscape changes every fifty metres from orchard to fish farm to rice paddy to village market. A private guide accompanies the ride with the ease and knowledge of a local, identifying the crops,$imp537$, $imp538$Stilted family home on a river island — genuine community stay, not a resort experience · Dawn fishing at 4:30am with the host family — the Mekong at its most authentic and beautiful · Cycling through flat delta rice paddies — meditative, scenic, and$imp538$, '$60–$100/person/night', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-MKG-CRU-4D3N-01', 'Mekong River Luxury Cruise (4 Days 3 Nights)', $imp539$Heritage Line | 18 passengers | Art gallery on board | Vietnam-Cambodia | Cai Rang$imp539$, '4 Days 3 Nights', 'Luxury River Cruise', 'Mekong Delta → Cambodia', 'Ultra Luxury', $imp540$**Day 1 — Embarkation: Saigon to the Delta** The luxury cruise begins in Saigon, where a private vehicle transfers guests from their hotel to the dock for embarkation on a vessel of exceptional comfort and design — a Mekong river cruise boat whose cabin quality, restaurant standards, and on-board service rival the finest boutique hotels, and whose position on the water provides a perspective on the delta that no land-based accommodation can approach. The first afternoon on the river covers the t$imp540$, $imp541$Heritage Line Mekong — 18 passengers maximum, Vietnamese art gallery on board · Crosses the Vietnam–Cambodia border by river — the route the great Mekong itself takes · Cai Rang Floating Market from ship's tender at 5am — the definitive floating mark$imp541$, '$350–$600/person/night', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-DAL-ADV-FD-01', 'Da Lat Adventure — Canyoning & Mountain Biking (Full Day)', $imp542$Phat Tire Ventures | Canyoning | Waterfall rappelling | Mountain biking | Pine forest$imp542$, 'Full Day', 'Adventure', 'Da Lat', 'Mid', $imp543$**Da Lat Adventure — Canyoning ****&**** Mountain Biking (Full Day)** Da Lat's highland landscape — waterfalls tumbling through pine forests, basalt canyon walls eroded by rivers whose source is in the mountains above — provides a natural adventure environment of exceptional quality, and a full day combining canyoning and mountain biking delivers two of its finest physical pleasures in a single exhilarating arc. The morning's canyoning descent involves rappelling down waterfall faces, swimming t$imp543$, $imp544$Phat Tire Ventures — #1 adventure operator in Da Lat, internationally safety-certified · Canyoning at Datanla: rappelling down active waterfalls through jungle gorges · Mountain biking through Da Lat's unique pine-forested highland landscape$imp544$, 'Mid', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-DAL-NAT-2D1N-01', 'Da Lat — Flower, Coffee & Highland Countryside (2 Days 1 Night)', $imp545$K'Ho Coffee | Ana Mandara Villas | Truc Lam Monastery | Flowers | Scenic highland$imp545$, '2 Days 1 Night', 'Nature & Culinary', 'Da Lat', 'Premium', $imp546$**Da Lat — Flower, Coffee ****&**** Highland Countryside (2 Days 1 Night)** **Day 1 — Flowers, Coffee, and Highland Atmosphere** Da Lat's claim to distinctiveness among Vietnam's destinations rests on several pillars simultaneously: the French colonial hill station architecture that gives its centre a European nostalgia unlike anything else in the country, the flower industry that supplies the entire nation with fresh blooms and perfumes the morning air with extraordinary sweetness, and the coff$imp546$, $imp547$K'Ho Coffee — indigenous-owned specialty coffee farm, farmer-direct single-origin experience · Ana Mandara Villas — historic French colonial villa resort, Da Lat's finest accommodation · Truc Lam Zen Monastery: cable car approach through pine forest,$imp547$, 'Premium', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-NTR-BCH-FD-01', 'Nha Trang — Island Hopping & Snorkelling (Full Day)', $imp548$Hon Mun | 4 islands | 15m visibility | PADI | Floating seafood lunch | Marine life$imp548$, 'Full Day', 'Nature & Beach', 'Nha Trang', 'Mid', $imp549$**Nha Trang — Island Hopping ****&**** Snorkelling (Full Day)** Nha Trang Bay's thirty-kilometre arc of white sand is backed by a ring of offshore islands whose shallow reefs support an ecosystem of extraordinary colour and diversity, and a private full day of island hopping and snorkelling in the company of an experienced marine guide reveals the underwater world of the South China Sea at its most immediately accessible and visually rewarding. A private boat departs the marina in the early morn$imp549$, $imp550$Hon Mun Marine Protected Area — 15m+ visibility, Vietnam's finest accessible coral snorkelling · Rainbow Divers PADI — certified instruction and safety for all experience levels · Floating seafood lunch on the bay — lobster, clams, snapper fresh from$imp550$, 'Mid', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-NTR-LUX-4D3N-01', 'Nha Trang Luxury Beach & Spa (4 Days 3 Nights)', $imp551$Six Senses Ninh Van Bay | Overwater villa | Speedboat access | Amanoi | World Top 10$imp551$, '4 Days 3 Nights', 'Luxury & Wellness', 'Nha Trang / Ninh Van Bay', 'Ultra Luxury', $imp552$**Nha Trang Luxury Beach ****&**** Spa (4 Days 3 Nights)** **Day 1 — Arrival on the Bay** Nha Trang's appeal as Vietnam's finest beach destination is immediately apparent from the moment the plane descends over a bay of such natural beauty — the crescentic beach, the offshore islands, the mountains behind — that the traveller who has been anticipating this moment is rarely disappointed by the reality. A private transfer from the airport delivers guests directly to a resort of exceptional quality$imp552$, $imp553$Six Senses Ninh Van Bay — World Top 10 resort, accessible only by speedboat, no roads · Overwater villas with private infinity pool and outdoor sky bathroom · Amanoi alternative (Ninh Hai): Aman Group Vietnam — minimalist perfection in limestone hill$imp553$, '$500–$1,500/night', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-CDO-LUX-3D2N-01', $imp554$Con Dao — Vietnam's Last Eden (3 Days 2 Nights)$imp554$, $imp555$Six Senses Con Dao | Sea turtles | National park | Pristine beaches | Colonial history$imp555$, '3 Days 2 Nights', 'Luxury & Eco', 'Con Dao Islands', 'Ultra Luxury', $imp556$**Day 1 — The Last Eden** Con Dao — an archipelago of sixteen islands lying 230 kilometres off the southern coast, once infamous as a French and South Vietnamese prison colony and now Vietnam's most pristine and undeveloped island destination — announces its difference from every other Vietnamese beach resort immediately upon arrival: the forest comes directly to the edge of the sea, the beaches are unmarked by sun loungers or jet skis, and the silence is broken only by birds and waves. A privat$imp556$, $imp557$Six Senses Con Dao — World Top 10 resort in Vietnam's most pristine island setting · Sea turtle nesting programme (June–September): participatory conservation with park rangers · Con Dao National Park: primary jungle, sea eagles, and one of Vietnam's$imp557$, '$500–$1,500/night', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-PHQ-BCH-3D2N-01', 'Phu Quoc Beach Escape (3 Days 2 Nights)', $imp558$Sao Beach | Fish sauce factory | Pepper plantation | Rainbow Divers | Night market$imp558$, '3 Days 2 Nights', 'Beach & Culture', 'Phu Quoc Island', 'Mid–Premium', $imp559$**Day 1 — Island Arrival** Phu Quoc's position in the warm Gulf of Thailand — its waters a shade of blue that seems to intensify as the plane descends — announces immediately that this is an island of considerable natural beauty, and the private transfer from the airport through lanes of pepper plantations and fish sauce factories delivers guests to their resort while providing the first glimpse of the local culture that makes the island more interesting than its beach reputation suggests. The a$imp559$, $imp560$Sao Beach — one of Vietnam's most beautiful beaches, noticeably quieter than the north · Phu Quoc fish sauce: Vietnam's finest nuoc mam, produced by traditional barrel fermentation · Rainbow Divers PADI — Vietnam's leading dive operator, Hon Thom ree$imp560$, 'Mid–Premium', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO products (code, name, logic, duration, category, destination, level, description, usp, price_from, region) VALUES ('AA-SV-PHQ-LUX-4D3N-01', 'Phu Quoc Luxury Island Escape (4 Days 3 Nights)', $imp561$JW Marriott island-within-island | Overwater villa | World-class spa | Golf | Private beach$imp561$, '4 Days 3 Nights', 'Luxury & Wellness', 'Phu Quoc Island', 'Ultra Luxury', $imp562$**Day 1 — Luxury Landing** The finest Phu Quoc experience begins from the airport door — a private vehicle to a resort of absolute distinction, the welcome designed not by a checklist but by people who understand that the transition from journey to rest is itself an experience worth getting right. The resort, selected for the quality of its beach position, its architecture's relationship to the natural landscape, and the genuine warmth of its service culture, provides the base from which four da$imp562$, $imp563$JW Marriott — Bensley-designed island-within-island: Asia's most inventive resort concept · Overwater villas with sunrise deck, plunge pool, and direct bay access · World-class spa incorporating Vietnamese traditional wellness in a sea-view setting$imp563$, '$500–$1,500/night', 'south') ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, logic = EXCLUDED.logic, duration = EXCLUDED.duration, category = EXCLUDED.category, destination = EXCLUDED.destination, level = EXCLUDED.level, description = EXCLUDED.description, usp = EXCLUDED.usp, price_from = EXCLUDED.price_from, region = EXCLUDED.region;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-N01', 'Nguyễn Thị Thu Trang', 'Trang N.', 'North', 'EN', 'History, Culture', 'National', 130, '★★★★★', 'Available', '', 21, 'Hanoi', '+84 915 453 114', 'trang1108@gmail.com', '', 'Techcombank · 13320226837012', '34A ngách 252 ngõ chợ Khâm Thiên, Đống Đa, Hà Nội', $imp564$Born in 1983 in Hanoi, Trang has been a fully qualified tour guide since 2005. Friendly, informative, funny, and patient — her excellent communication skills and deep cultural understanding make her outstanding. Favourite subjects: history, adventure, and culture. She enjoys exploring mountains, countryside, and city towns, finding authentic cultural experiences everywhere. Loves reading, watching comedy movies, and swimming.$imp564$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-N02', 'Vũ Ngọc Sơn', 'Son V.', 'North', 'EN', 'War History, Mountains', 'National', 95, '★★★★', 'Available', '', 8, 'Hanoi', '+84 979 483 899', 'sonnyvietnam90@gmail.com', '', 'MB Bank · 0979483899', '39A, Ngách 94/87 Thượng Thanh, Long Biên, Hà Nội', $imp565$Hailing from Hanoi, Son is known for his smart appearance and attention to detail — always dressing formally as a sign of respect for guests. His friendly and adaptable nature allows him to connect with both senior travellers and young adventurers. Deep knowledge of war history and naval topics makes him an excellent storyteller. Also loves guiding mountainous areas — his passion for hiking keeps him fit and strong.$imp565$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-N03', 'Phạm Thị Hương', 'Huong P.', 'North', 'EN', 'Culture, Art, History', 'National', 95, '★★★★', 'Available', '', 7, 'Hanoi', '+84 933 286 628', 'hp02091945@gmail.com', '', 'Vietcombank · 0011004291133', 'Hanoi', $imp566$Originally from Hai Duong, now living in Hanoi. Over 7 years of experience with a deep passion for culture, history, and art — sharing these topics in an engaging and insightful way. Known for being sociable, flexible, and patient. Listens carefully to guests needs and goes the extra mile to make them comfortable. Loves working with families and children, creating engaging and educational experiences.$imp566$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-N04', 'Nguyễn Thị Lan Anh', 'Lan Anh N.', 'North', 'EN', 'History, Culture', 'National', 80, '★★★★', 'Available', '', 0, 'Hanoi', '+84 934 667 984', 'pipivn@yahoo.com', '', 'Techcombank · 19033107934010', 'Ngõ 9 Đội Cung, Lê Đại Hành, Hai Bà Trưng, Hà Nội', $imp567$Lan Anh is a Hanoi-based guide with a warm and welcoming approach to touring. She brings a thoughtful and detailed style to every itinerary, ensuring guests leave with a genuine appreciation for Vietnamese culture and history.$imp567$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-N05', 'Nguyễn Tuấn Phong', 'Phong N.', 'North', 'EN', 'History, Culture', 'National', 80, '★★★★', 'Available', '', 0, 'Hanoi', '+84 902 186 845', 'nguyentuanphong3101@gmail.com', '', 'MB Bank · 866868681997', 'C204, 16 Trần Hưng Đạo, Phan Chu Trinh, Hoàn Kiếm, Hà Nội', $imp568$Phong is a Hanoi-based guide with a strong command of English and a genuine enthusiasm for connecting visitors with the depth of Vietnamese history and culture. Reliable, personable, and well-organised.$imp568$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C01', 'Hồ Quốc', 'Quoc H.', 'Central', 'EN', 'History, War Veterans', 'National', 120, '★★★★★', 'Available', '', 15, 'Hue', '+84 934 848 050', 'quocsusu@gmail.com', '', 'Vietcombank · 0161000297321', '4/6/15 Tôn Quang Phiệt, An Cựu, Huế', $imp569$Born and raised in Hue, Quoc has over 15 years of experience. He specialises in Vietnamese history and culture, and loves taking guests to explore the countryside around Hue, Phong Nha, and Quang Tri. His expertise in war history makes him excellent for veteran tours — he has hosted many war veteran guests. Caring, flexible, responsible, and with a great sense of humour.$imp569$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C02', 'Nguyễn Duy Quý', 'Quy N.', 'Central', 'EN', 'Culture, Cuisine, Families', 'National', 100, '★★★★', 'Available', '', 11, 'Hoi An', '+84 935 308 004', 'quynguyenduy.vnn@gmail.com', '', 'Vietcombank · 0651000802558', 'Sau UBND Phường Cửa Đại, Lý Thái Tông, Hội An, Quảng Nam', $imp570$Born in Hoi An, guiding since 2015. Passionate about Vietnamese culture and cuisine, particularly in his hometown. Known for flexibility and quick problem-solving skills. A natural talent for taking care of and entertaining children — ideal guide for families. Loves introducing guests to local flavours, traditions, and history.$imp570$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C03', 'Lê Tấn Nhân', 'Nhan L.', 'Central', 'EN, ES', 'History, Culture, Calligraphy', 'National', 125, '★★★★★', 'Available', '', 15, 'Hue', '+84 912 312 712', 'tannhan2011@gmail.com', '', 'Vietcombank · 0161000790599', '6/105 Lê Ngô Cát, Tp. Huế', $imp571$Senior guide with 15 years of experience in Hue, Da Nang, and Hoi An. Originally trained as an English language teacher. Widely recognised for enthusiasm, humour, and patience. Also a skilled calligrapher — a talent he sees as his mission to preserve. Speaks English and Spanish. Consistently receives excellent feedback for professionalism and warm hospitality.$imp571$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C04', 'Nguyễn Nhật Lê Huy', 'Huy N.', 'Central', 'EN', 'Culture, History, Hue', 'National', 80, '★★★★', 'Available', '', 0, 'Hue', '+84 903 549 480', 'huylee612@gmail.com', '', 'Vietcombank · 0161001608319', '1/42 Trần Quang Khải, Tp. Huế, Thừa Thiên Huế', $imp572$Born and raised in Hue in a hardworking family. Calm, patient, and flexible — he loves sharing the rich culture, history, and scenery of his region. Special love for travelling and tasting good food, and enjoys outdoor activities during dry seasons. Strives to bring different and personal experiences to guests even at the most popular sites.$imp572$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C05', 'Trần Trung Nguyên', 'Win T.', 'Central', 'EN', 'History, Food, Hoi An', 'National', 110, '★★★★★', 'Available', '', 12, 'Hoi An', '+84 935 334 871', 'trantrungnguyen1991@gmail.com', '', 'Vietcombank · 0651000771942', '42 Nguyễn Khoa, Cẩm Nam, Hội An, Quảng Nam', $imp573$Known as "Win", born and raised in Hoi An — a place he considers a part of his heart. Licensed international guide since 2014. Open-minded, easy-going, and friendly with a great sense of humour. Deep knowledge of Hoi An, My Son, Marble Mountains, and Hue. Passionate about the Vietnam War and participated in volunteer and cultural exchange programmes.$imp573$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C06', 'Hồ Văn Hoàng', 'Brian H.', 'Central', 'EN', 'History, Culture, Hue', 'National', 125, '★★★★★', 'Available', '', 16, 'Hue', '+84 905 898 939', 'BRIANVIETNAM7@gmail.com', '', 'Vietcombank · 0161000339678', '1/3 Kiệt 177 Hàn Mặc Tử, Vỹ Dạ, Tp. Huế', $imp574$Known as Brian. Born and raised in Hue City, 16 years as a professional guide. Deep understanding of culture, history, customs, cuisine, and geopolitics. Fluent English, flexible itineraries, and excellent problem-solving. Customises tours based on guests interests and especially enjoys hosting families with children.$imp574$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C07', 'Võ Thị Thanh Thúy', 'Ms. Thuy V.', 'Central', 'EN', 'History, Craft Villages', 'National', 85, '★★★★★', 'Available', '', 0, 'Hue', '+84 935 212 233', 'Thanhthuyvo2303@gmail.com', '', 'VPBank · 99212233', '61 Đào Duy Anh, Thuận Lộc, Tp. Huế', $imp575$Grew up in a traditional village surrounded by craft communities, developing an early love for local customs and stories. Her warm storytelling makes historical topics easy to understand. Positive and uplifting, she connects naturally with families and children — parents often say their children remember "Ms. Thuy" long after the trip ends. Dedicated to learning from elders, artisans, and local communities.$imp575$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C08', 'Trương Văn Hòa', 'Tommy T.', 'Central', 'EN', 'Culture, Rural Life, Hoi An', 'National', 80, '★★★★', 'Available', '', 0, 'Hoi An', '+84 971 090 013', 'hoa.truong054@gmail.com', '', 'OCB Bank · 0151100000298006', 'Hẻm 116 Nguyễn Chí Thanh, Cẩm Hà, Hội An, Quảng Nam', $imp576$Known as Tommy, he has spent his life immersed in the culture and traditions of Central Vietnam. As a father, he has a special ability to connect with families and children — patient, caring, and attentive. Deep knowledge of agriculture and rural lifestyles. Loves guiding Hoi An Ancient Town, the countryside, and any other site assigned. Friendly, flexible, and wholly guest-focused.$imp576$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
