INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-C10', 'Lê Quốc Đạt', 'Dat L.', 'Central', 'EN', 'History, Photography, Nature', 'National', 80, '★★★★', 'Available', '', 0, 'Hue', '+84 355 132 588', 'quocdattourguide@gmail.com', '', 'MB Bank · 0355132588', '8/162 Nguyễn Sinh Cung, Vỹ Dạ, TP Huế', $imp578$Born in 1999 in Quảng Bình, young and energetic guide based in Huế. Friendly, approachable, and open-minded. Passionate about history, photography, and food. Excels guiding Hue Imperial City, Royal Tombs, Marble Mountains, Da Nang, and Hoi An. He does not just guide tours — he creates memorable experiences through genuine connection.$imp578$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
