INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-S01', 'Phạm Tấn Tài', 'Tai P.', 'South', 'EN', 'Mekong Delta, Culture', 'National', 125, '★★★★★', 'Available', '', 13, 'Saigon', '+84 909 584 560', 'tai@incountrytours.com', 'L', 'Agribank · 6702295123689', '141/2/6c Nguyễn Thái Học, Long Xuyên, An Giang', $imp580$Guiding since 2013, Tai comes from Chau Doc on the Vietnam-Cambodia border. Achieved a Masters degree in English in 2018 while guiding. Known for enthusiasm, energy, and sociable nature — open-minded, calm, and fun. Interests include Tai Chi (nicknamed "Tai-Chi 7"), flute, running, and cycling. Focuses on local life and traditions for authentic and immersive experiences.$imp580$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
