INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-S04', 'Trương Quang Minh', 'Mark T.', 'South', 'EN', 'History, Culture, Saigon', 'National', 80, '★★★★', 'Available', '', 0, 'Saigon', '+84 368 564 496', 'truongquangminh99travelguide@gmail.com', '', 'TP Bank · 0368564496', '18-20 Phan Ngữ, Đa Kao, Quận 1, TP.HCM', $imp583$Known as Mark, born 2000 in Ho Chi Minh City. Determined, perfectionist, and believes in lifelong learning. Has cultivated public speaking, singing, and MC skills. Loves showcasing all regions of Vietnam. Also learning Chinese. Enjoys working with families and children.$imp583$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-S05', 'Lê Thị Hằng Nga', 'Nga L.', 'South', 'EN', 'Family, Hospitality', 'National', 110, '★★★★★', 'Available', '', 10, 'Saigon', '+84 979 639 403', 'minhtambui2016@gmail.com', '', 'MB Bank HCMC · 7788699699699', 'Rainbow Vinhomes Grand Park, Q9, TP HCM', $imp584$Born in Di Linh, Central Highlands, now in Saigon. Former flight attendant for 10 years — extensive travel and exceptional communication skills. Devoted mother of three. Lives by "work hard, play hard." Positive, friendly, and strong work ethic. Special love for working with families and children.$imp584$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-S06', 'Đậu Công Đức Anh', 'Duc Anh D.', 'South', 'EN', 'History, Saigon, Humour', 'National', 100, '★★★★', 'Available', '', 10, 'Saigon', '+84 933 778 821', 'ducanhtravel2110@gmail.com', '', 'Vietcombank · 0071001066347', '63 Lê Thị Hồng, Phường 17, Gò Vấp', $imp585$Native Saigonese with over a decade of guiding. Started in the backpacker market, transitioned to high-end guests. Also leads outbound trips to Australia. Known for his humour and lively personality — believes happiness is essential. Deep passion for Vietnamese history and culture. Brings enthusiasm and a warm sense of humour to every journey.$imp585$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-S07', 'Duy Anh Khoa', 'Khoa D.', 'South', 'EN', 'Saigon, Mekong Delta', 'National', 80, '★★★★', 'Available', '', 0, 'Saigon', '+84 931 746 311', 'zetduyanhkhoa@gmail.com', '', 'Techcombank · 19034162400013', '73/53 Huỳnh Văn Bánh, Phú Nhuận, TP HCM', $imp586$Born and raised in Saigon. Friendly, outgoing, energetic, and ambitious — always striving to do his best. Favourite place to guide is his hometown — Ho Chi Minh City. Believes more tours should highlight the Mekong Delta for its rich blend of ethnic cultures, stunning landscapes, rivers, rice fields, temples, and islands.$imp586$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
INSERT INTO guides (id, full_name, english_name, region, languages, specialty, license_number, daily_rate, rating, status, photo_url, years_exp, location, phone, email, shirt_size, bank_account, address, bio) VALUES ('G-S08', 'Nguyễn Thị Thúy Nguyên', 'Mai N.', 'South', 'EN', 'Food, Culture, Families', 'National', 85, '★★★★', 'Available', '', 2, 'Saigon', '+84 905 709 599', 'maimaing21@gmail.com', '', 'BIDV · 5510736161', '76a/2/3 Trần Hữu Trang, Phú Nhuận, HCM', $imp587$Known as Mai. Guide License #179236164 (valid 04/03/2028). Cheerful, patient, and culturally passionate. Deep love for Vietnamese food and culture — tours are both enriching and full of heart. Especially great with families and children. Enjoys reading, playing ukulele, and podcasts. Calm, positive, and welcoming.$imp587$) ON CONFLICT (id) DO UPDATE SET full_name = EXCLUDED.full_name, english_name = EXCLUDED.english_name, region = EXCLUDED.region, languages = EXCLUDED.languages, specialty = EXCLUDED.specialty, license_number = EXCLUDED.license_number, daily_rate = EXCLUDED.daily_rate, rating = EXCLUDED.rating, status = EXCLUDED.status, photo_url = EXCLUDED.photo_url, years_exp = EXCLUDED.years_exp, location = EXCLUDED.location, phone = EXCLUDED.phone, email = EXCLUDED.email, shirt_size = EXCLUDED.shirt_size, bank_account = EXCLUDED.bank_account, address = EXCLUDED.address, bio = EXCLUDED.bio;
