INSERT INTO feedback (id, type, feedback_date, booking_id, client_name, nps, overall_rating, guide_rating, hotel_rating, best_moment, improvement, comments, would_return) VALUES ('FB-001', 'client', '2026-04-18', NULL, 'Sarah Mitchell', 10, 5, 5, 5, $imp596$The private Halong Bay sunrise moment — absolutely magical. Nothing like this at home in New York.$imp596$, '', $imp597$Minh was the best guide we have ever had anywhere in the world. We are already planning to come back.$imp597$, 'yes') ON CONFLICT (id) DO UPDATE SET type = EXCLUDED.type, feedback_date = EXCLUDED.feedback_date, booking_id = EXCLUDED.booking_id, client_name = EXCLUDED.client_name, nps = EXCLUDED.nps, overall_rating = EXCLUDED.overall_rating, guide_rating = EXCLUDED.guide_rating, hotel_rating = EXCLUDED.hotel_rating, best_moment = EXCLUDED.best_moment, improvement = EXCLUDED.improvement, comments = EXCLUDED.comments, would_return = EXCLUDED.would_return;
INSERT INTO feedback (id, type, feedback_date, booking_id, client_name, nps, overall_rating, guide_rating, hotel_rating, best_moment, improvement, comments, would_return) VALUES ('FB-002', 'client', '2026-04-22', NULL, 'Jean-Pierre Moreau', 9, 5, 5, 4, $imp598$La Siesta Hoi An and the cooking class — exceeded expectations. Superb attention to detail.$imp598$, 'Transfer from Da Nang airport could be more clearly communicated.', $imp599$Très professionnel. We will definitely recommend The Ant Adventures to our friends in Paris.$imp599$, 'yes') ON CONFLICT (id) DO UPDATE SET type = EXCLUDED.type, feedback_date = EXCLUDED.feedback_date, booking_id = EXCLUDED.booking_id, client_name = EXCLUDED.client_name, nps = EXCLUDED.nps, overall_rating = EXCLUDED.overall_rating, guide_rating = EXCLUDED.guide_rating, hotel_rating = EXCLUDED.hotel_rating, best_moment = EXCLUDED.best_moment, improvement = EXCLUDED.improvement, comments = EXCLUDED.comments, would_return = EXCLUDED.would_return;
INSERT INTO feedback (id, type, feedback_date, booking_id, client_name, nps, overall_rating, guide_rating, hotel_rating, best_moment, improvement, comments, would_return) VALUES ('FB-003', 'client', '2026-04-28', NULL, 'James Thornton', 8, 4, 4, 4, 'Cycling through the rice paddies — pure Vietnam. Very authentic experience.', 'Day 3 itinerary felt slightly rushed. Would have loved more time at Hue Citadel.', $imp600$Great overall. Minor timing issues but nothing that ruined the trip. Would recommend.$imp600$, 'yes') ON CONFLICT (id) DO UPDATE SET type = EXCLUDED.type, feedback_date = EXCLUDED.feedback_date, booking_id = EXCLUDED.booking_id, client_name = EXCLUDED.client_name, nps = EXCLUDED.nps, overall_rating = EXCLUDED.overall_rating, guide_rating = EXCLUDED.guide_rating, hotel_rating = EXCLUDED.hotel_rating, best_moment = EXCLUDED.best_moment, improvement = EXCLUDED.improvement, comments = EXCLUDED.comments, would_return = EXCLUDED.would_return;
INSERT INTO feedback (id, type, feedback_date, booking_id, client_name, nps, overall_rating, guide_rating, hotel_rating, best_moment, improvement, comments, would_return) VALUES ('FB-004', 'client', '2026-05-02', NULL, 'Charu (ILV Group)', 10, 5, 5, 5, $imp601$Delta cycling route was perfectly curated for our group. Every detail was handled seamlessly.$imp601$, '', $imp602$As a B2B agent sending clients regularly, this group has set the benchmark. Will be sending more bookings.$imp602$, 'yes') ON CONFLICT (id) DO UPDATE SET type = EXCLUDED.type, feedback_date = EXCLUDED.feedback_date, booking_id = EXCLUDED.booking_id, client_name = EXCLUDED.client_name, nps = EXCLUDED.nps, overall_rating = EXCLUDED.overall_rating, guide_rating = EXCLUDED.guide_rating, hotel_rating = EXCLUDED.hotel_rating, best_moment = EXCLUDED.best_moment, improvement = EXCLUDED.improvement, comments = EXCLUDED.comments, would_return = EXCLUDED.would_return;
INSERT INTO feedback (id, type, feedback_date, booking_id, client_name, nps, overall_rating, guide_rating, hotel_rating, best_moment, improvement, comments, would_return) VALUES ('FB-005', 'client', '2026-05-06', NULL, 'Emma van der Berg', 7, 4, 4, 3, 'Street food tour in Hanoi Old Quarter — unforgettable.', 'Hotel in Ninh Binh was slightly below expectations for the price point.', $imp603$Good trip overall. Some elements were exceptional, others felt average for a luxury product.$imp603$, 'maybe') ON CONFLICT (id) DO UPDATE SET type = EXCLUDED.type, feedback_date = EXCLUDED.feedback_date, booking_id = EXCLUDED.booking_id, client_name = EXCLUDED.client_name, nps = EXCLUDED.nps, overall_rating = EXCLUDED.overall_rating, guide_rating = EXCLUDED.guide_rating, hotel_rating = EXCLUDED.hotel_rating, best_moment = EXCLUDED.best_moment, improvement = EXCLUDED.improvement, comments = EXCLUDED.comments, would_return = EXCLUDED.would_return;
INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('LOG-V-001', 'visa', 'Visa Services', 'Vietnam E-Visa Express', 'E-Visa Express', 'Mr. Tran Huu Duc', '+84 90 111 2233', 'support@evisa-express.vn', 'Hanoi (Nationwide)', 'national', '$45/application · $120 urgent 24hr', 'USD', '100% upfront', true, 'Non-refundable once submitted', 'Licensed by Ministry of Public Security', 'Mon–Sat 8am–8pm. Urgent 24/7.', $imp604$Preferred e-visa partner handling 95%+ approval rate. Specialises in complex cases: dual nationality, prior refusals, business multi-entry. Dedicated account manager for The Ant Adventures.$imp604$, 'Has back channel for escalation on edge cases. Very reliable.', '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
