INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('WAT-001', 'river', 'River Sampan — Ninh Binh', 'Tam Coc Wooden Sampan Fleet', 'Tam Coc Sampans', 'Mrs. Huong Nguyen', '+84 93 333 4455', 'huong@tamcoc-boats.vn', 'Ninh Binh', 'north', '$85/boat/2hr (max 2 pax) · $140 sunset', 'USD', 'Day of trip', false, 'Free cancellation 24hr', 'Provincial boat licence', 'Daily 6am–5pm, weather dependent', $imp607$Fleet of traditional hand-carved wooden sampans for the Tam Coc gorge and Van Long Nature Reserve. Rowed by local women — extraordinary cultural encounter. Private bookings only for The Ant Adventures clients.$imp607$, $imp608$Request Mrs. Huong personally — she rows the most scenic route and knows the caves intimately.$imp608$, '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
