INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('WAT-002', 'coastal', 'Coastal Speedboat — Con Dao', 'Con Dao Marine Charters', 'Con Dao Speedboats', 'Mr. Vinh Ha', '+84 95 444 5566', 'vinh@condaomarine.com', 'Con Dao Island', 'south', '$280/half-day (max 8 pax) · $480/full-day', 'USD', '50% deposit', true, '72hr notice', 'MCA licensed, insured to $2M', 'Oct–Apr optimal. Nov–Jan peak.', $imp609$Private speedboat charters for Con Dao archipelago — sea turtle nesting beaches, coral reef snorkelling, deserted island picnic drops. Completely private.$imp609$, $imp610$The only private charter allowed inside the national park buffer zone. Unique access.$imp610$, '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
