INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('ADV-C-001', 'cycling', 'Road Cycling', 'IndoChina Cycling Co.', 'IndoChina Cycling', 'Mr. James Tran', '+84 96 555 6677', 'james@indochinacycling.com', 'Hoi An (Nationwide)', 'national', '$45/bike/day (road) · $60/bike/day (MTB)', 'USD', 'Invoice 7 days', true, 'Free 48hr', 'Trek-certified fleet, liability insured', 'Year-round. Advance booking for 8+ bikes.', $imp611$Premium road and mountain bike fleet. Custom fit, helmet, GPS, repair kit included. Mobile maintenance vehicle follows groups of 4+. Certified for Ha Giang Loop, Mekong Delta, and Hoi An countryside.$imp611$, 'Our top cycling partner. James speaks perfect English and is an ex-pro cyclist.', '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
