INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('EXP-A-001', 'artisan', 'Master Artisan', 'Mr. Nguyễn Văn Khánh — Ca Trú Master', 'Mr. Khanh', 'Mr. Khanh', '+84 90 123 9876', 'khanh.catru@gmail.com', 'Hanoi', 'north', '$280/private session (up to 4 pax)', 'USD', 'Cash on day', false, '48hr notice', 'N/A — individual artist', 'Tue, Thu, Sat evenings', $imp614$UNESCO-listed ca trú chamber music master. Grants exclusive private access to his practice space for an intimate performance and conversation. Impossible to book independently — The Ant Adventures exclusive.$imp614$, $imp615$Must request 2 weeks in advance. He limits to 2 groups per week. Don't put in group tours.$imp615$, '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
