INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('EXP-E-001', 'events', 'Private Dinner Decorator', 'Phuong Decor & Events Hoi An', 'Phuong Events', 'Ms. Phuong Le', '+84 91 987 6543', 'phuong@decor-hoian.com', 'Hoi An', 'central', '$380 standard · $680 premium (lanterns, florals, music)', 'USD', '50% deposit', true, '72hr notice', 'Venue-covered', 'All days except Tet', $imp616$Luxury private dining and event setup specialists. Beach dinners, garden lantern events, rooftop floral installations. Custom sound, lighting, and staging. Trusted for honeymoons, anniversaries, and proposal setups.$imp616$, $imp617$Phuong personally oversees every Ant Adventures event. Ask for the hibiscus & jasmine package.$imp617$, '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
