INSERT INTO suppliers (id, category, subcategory, name, english_name, contact_name, phone, email, location, region, rate, currency, payment_terms, has_contract, cancellation_policy, insurance_info, availability, description, notes, rating, status) VALUES ('PER-M-001', 'media', 'Travel Photographer', 'Hoàng Quốc Tuấn Photography', 'Tuan H.', 'Tuan Hoang', '+84 96 789 0123', 'tuan.photography@gmail.com', 'Hanoi / Sapa', 'north', '$200/half-day · $350/full-day (incl. edited images)', 'USD', '50% deposit', false, 'Free 48hr', 'Equipment insured', 'Most dates. Book 1 week ahead.', $imp619$National Geographic Vietnam award-winning photographer, 15 years experience. Photography-specific tours to best light spots at the right times. Teaches guests to capture Vietnam's light.$imp619$, 'Work published in NG, Condé Nast Traveller, and Lonely Planet.', '★★★★★', 'Active') ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, subcategory = EXCLUDED.subcategory, name = EXCLUDED.name, english_name = EXCLUDED.english_name, contact_name = EXCLUDED.contact_name, phone = EXCLUDED.phone, email = EXCLUDED.email, location = EXCLUDED.location, region = EXCLUDED.region, rate = EXCLUDED.rate, currency = EXCLUDED.currency, payment_terms = EXCLUDED.payment_terms, has_contract = EXCLUDED.has_contract, cancellation_policy = EXCLUDED.cancellation_policy, insurance_info = EXCLUDED.insurance_info, availability = EXCLUDED.availability, description = EXCLUDED.description, notes = EXCLUDED.notes, rating = EXCLUDED.rating, status = EXCLUDED.status;
