INSERT INTO dev_notes (id, title, priority, category, assignee, status, note_date, author, body) VALUES ('DN-001', 'Add PDF export for Tour Proposals', 'high', 'feature', 'Dev Team', 'open', '2026-05-04', 'Tai Pham', $imp621$In Tour Design Step 4, after the AI generates the itinerary proposal, add a button to download it as a formatted PDF. Should include: The Ant Adventures header with green branding, client name, tour summary, day-by-day, pricing table, and footer with contact info. Similar to the Guide Bio download that already works.$imp621$) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, priority = EXCLUDED.priority, category = EXCLUDED.category, assignee = EXCLUDED.assignee, status = EXCLUDED.status, note_date = EXCLUDED.note_date, author = EXCLUDED.author, body = EXCLUDED.body;
INSERT INTO dev_notes (id, title, priority, category, assignee, status, note_date, author, body) VALUES ('DN-002', 'Clients page — add quick filter for anniversary/honeymoon', 'medium', 'feature', 'Dev Team', 'open', '2026-05-04', 'Tai Pham', $imp622$In the Clients page, add a filter dropdown for Travel Style that includes Honeymoon and Anniversary as separate options. This helps the sales team quickly identify which clients need special touches like room decorations, champagne, etc.$imp622$) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, priority = EXCLUDED.priority, category = EXCLUDED.category, assignee = EXCLUDED.assignee, status = EXCLUDED.status, note_date = EXCLUDED.note_date, author = EXCLUDED.author, body = EXCLUDED.body;
INSERT INTO dev_notes (id, title, priority, category, assignee, status, note_date, author, body) VALUES ('DN-003', 'Weather Guide — add rain days count per month', 'low', 'data', 'Dev Team', 'open', '2026-05-04', 'Tai Pham', $imp623$In the Weather Guide grid, each cell currently shows Excellent/Good/Fair/Poor. Please also add an average number of rainy days per month (e.g. "3 days") so the sales team can advise clients more precisely.$imp623$) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, priority = EXCLUDED.priority, category = EXCLUDED.category, assignee = EXCLUDED.assignee, status = EXCLUDED.status, note_date = EXCLUDED.note_date, author = EXCLUDED.author, body = EXCLUDED.body;
